# Default configuration (can be overridden before sourcing)
: "${GITHUB_REPO:=prestonbrown/helixscreen}"
: "${INSTALL_DIR:=/opt/helixscreen}"
: "${SERVICE_NAME:=helixscreen}"

# Well-known paths (used by uninstall, clean, stop_service)
# AD5M: /opt/helixscreen, /root/printer_software/helixscreen, /srv/helixscreen (ZMOD)
# K1: /usr/data/helixscreen
# Pi: /opt/helixscreen
# CC1 (COSMOS): /user-resource/helixscreen (/ is RO squashfs)
# Snapmaker U1: /userdata/helixscreen
HELIX_INSTALL_DIRS="/root/printer_software/helixscreen /opt/helixscreen /usr/data/helixscreen /srv/helixscreen /user-resource/helixscreen /userdata/helixscreen"

# Init script locations vary by platform/firmware
# AD5M Klipper Mod: S80, AD5M Forge-X: S90, K1: S99, CC1 (COSMOS): plain /etc/init.d/helixscreen
HELIX_INIT_SCRIPTS="/etc/init.d/S80helixscreen /etc/init.d/S90helixscreen /etc/init.d/S99helixscreen /etc/init.d/helixscreen"

# HelixScreen process names (order matters: watchdog first to prevent crash dialog)
HELIX_PROCESSES="helix-watchdog helix-screen helix-splash"

# Returns true when install.sh was spawned by helix-screen's in-app update.
# Used by multiple modules (service.sh, competing_uis.sh) to skip operations
# that are unnecessary or destructive during self-update.
# Set by update_checker.cpp before execv().
_is_self_update() {
    [ "${HELIX_SELF_UPDATE:-}" = "1" ]
}

# Get sudo prefix needed for a file operation.
# Returns empty string if current user has write access, $SUDO otherwise.
# For existing files, checks file writability. For new files, checks parent dir.
# This avoids creating root-owned files in user-writable directories.
file_sudo() {
    local path="$1"
    if [ -e "$path" ]; then
        [ -w "$path" ] && echo "" || echo "$SUDO"
    else
        local dir
        dir="$(dirname "$path")"
        [ -w "$dir" ] && echo "" || echo "$SUDO"
    fi
}

# Track what we've done for cleanup
CLEANUP_TMP=false
CLEANUP_SERVICE=false
BACKUP_CONFIG=""
BACKUP_ENV=""
ORIGINAL_INSTALL_EXISTS=false

# Colors (if terminal supports it)
setup_colors() {
    if [ -t 1 ]; then
        RED='\033[0;31m'
        GREEN='\033[0;32m'
        YELLOW='\033[1;33m'
        CYAN='\033[0;36m'
        BOLD='\033[1m'
        NC='\033[0m'
    else
        RED=''
        GREEN=''
        YELLOW=''
        CYAN=''
        BOLD=''
        NC=''
    fi
}

# Initialize colors immediately
setup_colors

# Logging functions (printf %b interprets \033 escapes; BusyBox echo does not)
log_info() { printf '%b\n' "${CYAN}[INFO]${NC} $1" >&2; }
log_success() { printf '%b\n' "${GREEN}[OK]${NC} $1" >&2; }
log_warn() { printf '%b\n' "${YELLOW}[WARN]${NC} $1" >&2; }
log_error() { printf '%b\n' "${RED}[ERROR]${NC} $1" >&2; }

# Error handler - cleanup and report what went wrong
# Usage: trap 'error_handler $LINENO' ERR
error_handler() {
    local exit_code=$?
    local line_no=$1

    echo ""
    log_error "=========================================="
    log_error "Installation FAILED at line $line_no"
    log_error "Exit code: $exit_code"
    log_error "=========================================="
    echo ""

    # Restore backups BEFORE cleaning TMP_DIR — backup files live in TMP_DIR.
    # Try TMP_DIR backup first, then fall back to .old directory (survives PrivateTmp).
    $(file_sudo "${INSTALL_DIR}") mkdir -p "${INSTALL_DIR}/config" 2>/dev/null || true

    if [ ! -f "${INSTALL_DIR}/config/settings.json" ]; then
        local _restored=false
        # Try TMP_DIR backup
        if [ -n "$BACKUP_CONFIG" ] && [ -f "$BACKUP_CONFIG" ]; then
            log_info "Restoring backed up configuration..."
            if $(file_sudo "${INSTALL_DIR}/config") cp "$BACKUP_CONFIG" "${INSTALL_DIR}/config/settings.json" 2>/dev/null; then
                log_success "Configuration restored from backup"
                _restored=true
            fi
        fi
        # Fallback: .old directory (try new name first, then legacy)
        if [ "$_restored" = false ] && [ -n "${INSTALL_BACKUP:-}" ]; then
            if [ -f "${INSTALL_BACKUP}/config/settings.json" ]; then
                if $(file_sudo "${INSTALL_DIR}/config") cp "${INSTALL_BACKUP}/config/settings.json" "${INSTALL_DIR}/config/settings.json" 2>/dev/null; then
                    log_success "Configuration restored from previous install"
                    _restored=true
                fi
            elif [ -f "${INSTALL_BACKUP}/config/helixconfig.json" ]; then
                if $(file_sudo "${INSTALL_DIR}/config") cp "${INSTALL_BACKUP}/config/helixconfig.json" "${INSTALL_DIR}/config/settings.json" 2>/dev/null; then
                    log_success "Configuration restored from previous install (migrated from helixconfig.json)"
                    _restored=true
                fi
            elif [ -f "${INSTALL_BACKUP}/helixconfig.json" ]; then
                if $(file_sudo "${INSTALL_DIR}/config") cp "${INSTALL_BACKUP}/helixconfig.json" "${INSTALL_DIR}/config/settings.json" 2>/dev/null; then
                    log_success "Configuration restored from previous install (legacy root location)"
                    _restored=true
                fi
            fi
        fi
        if [ "$_restored" = false ]; then
            log_warn "Could not restore config from any backup source"
        fi
    fi

    if [ ! -f "${INSTALL_DIR}/config/helixscreen.env" ]; then
        if [ -n "$BACKUP_ENV" ] && [ -f "$BACKUP_ENV" ]; then
            if $(file_sudo "${INSTALL_DIR}/config") cp "$BACKUP_ENV" "${INSTALL_DIR}/config/helixscreen.env" 2>/dev/null; then
                log_success "helixscreen.env restored"
            fi
        elif [ -n "${INSTALL_BACKUP:-}" ] && [ -f "${INSTALL_BACKUP}/config/helixscreen.env" ]; then
            if $(file_sudo "${INSTALL_DIR}/config") cp "${INSTALL_BACKUP}/config/helixscreen.env" "${INSTALL_DIR}/config/helixscreen.env" 2>/dev/null; then
                log_success "helixscreen.env restored from previous install"
            fi
        fi
    fi

    # Cleanup temporary files after restores are done
    if [ "$CLEANUP_TMP" = true ] && [ -d "$TMP_DIR" ]; then
        rm -rf "$TMP_DIR"
    fi

    echo ""
    log_error "Installation was NOT completed."
    log_error "Your system should be in its original state."
    echo ""
    log_info "For help, please:"
    log_info "  1. Check the error message above"
    log_info "  2. Verify network connectivity"
    log_info "  3. Report issues at: https://github.com/${GITHUB_REPO}/issues"
    echo ""

    exit $exit_code
}

# Cleanup function for normal exit
cleanup_on_success() {
    if [ -d "$TMP_DIR" ]; then
        rm -rf "$TMP_DIR"
    fi
}

# Kill process(es) by name — SIGTERM first, then SIGKILL any survivors.
# helix-watchdog and helix-screen catch SIGTERM but don't always exit (e.g.
# during splash handoff or when blocked on I/O), so the installer must
# escalate or uninstall leaves zombie processes behind (#xxx observed on CC1).
# Works on both GNU systems and BusyBox (AD5M/K1/CC1).
# Args: process_name [process_name2 ...]
# Returns: 0 if any process was killed, 1 if none found
kill_process_by_name() {
    local killed_any=false
    local proc pids pid

    for proc in "$@"; do
        pids=$(pidof "$proc" 2>/dev/null || true)
        if [ -n "$pids" ]; then
            for pid in $pids; do
                $SUDO kill "$pid" 2>/dev/null || true
            done
            killed_any=true
        fi
    done

    [ "$killed_any" = true ] || return 1

    # Give caught-SIGTERM handlers a moment, then SIGKILL any survivors.
    sleep 1
    for proc in "$@"; do
        pids=$(pidof "$proc" 2>/dev/null || true)
        if [ -n "$pids" ]; then
            for pid in $pids; do
                $SUDO kill -9 "$pid" 2>/dev/null || true
            done
        fi
    done

    return 0
}

# Remove HelixScreen state directories that hold rolling config backups and
# update markers. These survive a normal install because they live OUTSIDE
# INSTALL_DIR by design — they need to survive Moonraker's rmtree of the
# install dir during in-app updates (see app_constants.h: Update namespace).
#
# On --uninstall and --clean the user has signaled they want a clean slate,
# so we sweep them here. Live config under printer_data/config/helixscreen/
# is handled separately by remove_config_symlink / clean_old_installation.
# The dot-prefix is the bright line: dotted = our state, undotted = live config.
#
# Paths swept (all are ours; we own these names):
#   /var/lib/helixscreen          (systemd StateDirectory=helixscreen)
#   $INSTALL_PARENT/.helixscreen  (self_restart_sentinel from helixscreen-update.service)
#   $KLIPPER_HOME/.helixscreen    (HOME-based fallback when no StateDirectory)
#   /root/.helixscreen            (always swept; service may have run as root
#                                  on a prior install regardless of current user)
#
# Reads: INSTALL_DIR, KLIPPER_HOME, SUDO,
#        HELIX_STATE_VAR_LIB (default /var/lib/helixscreen),
#        HELIX_STATE_ROOT_HOME (default /root/.helixscreen)
# Writes: (none)
clean_helix_state_dirs() {
    local install_parent
    # The two hardcoded paths are env-overrideable so the BATS suite can
    # redirect them at test-tmpdir paths instead of touching real /var/lib
    # and /root content. Production callers leave them unset.
    local state_var_lib="${HELIX_STATE_VAR_LIB:-/var/lib/helixscreen}"
    local state_root_home="${HELIX_STATE_ROOT_HOME:-/root/.helixscreen}"

    log_info "Removing HelixScreen state directories (rolling config backups)..."

    # systemd StateDirectory= target
    if [ -d "$state_var_lib" ]; then
        $SUDO rm -rf "$state_var_lib"
        log_success "Removed $state_var_lib"
    fi

    # $INSTALL_PARENT/.helixscreen — self_restart_sentinel (helixscreen-update.service).
    # Skip when INSTALL_DIR is unset or dirname would resolve to "/" or "." (defensive
    # against misuse from outside our normal install flow; current HELIX_INSTALL_DIRS
    # all have a real parent dir).
    if [ -n "${INSTALL_DIR:-}" ]; then
        install_parent=$(dirname "$INSTALL_DIR")
        case "$install_parent" in
            /|.|"") : ;;
            *)
                if [ -d "${install_parent}/.helixscreen" ]; then
                    $SUDO rm -rf "${install_parent}/.helixscreen"
                    log_success "Removed ${install_parent}/.helixscreen"
                fi
                ;;
        esac
    fi

    # Service user's $HOME/.helixscreen (fallback backup path)
    if [ -n "${KLIPPER_HOME:-}" ] && [ -d "${KLIPPER_HOME}/.helixscreen" ]; then
        $SUDO rm -rf "${KLIPPER_HOME}/.helixscreen"
        log_success "Removed ${KLIPPER_HOME}/.helixscreen"
    fi

    # /root/.helixscreen — always sweep. The directory name is ours (dot-prefix rule);
    # rm -rf on a missing dir is a no-op, and this catches platforms where the service
    # historically ran as root even if KLIPPER_HOME has since moved off /root.
    if [ -d "$state_root_home" ]; then
        $SUDO rm -rf "$state_root_home"
        log_success "Removed $state_root_home"
    fi
}

# Print post-install commands for the user
# Reads: INIT_SYSTEM, SERVICE_NAME, INIT_SCRIPT_DEST, INSTALL_DIR
print_post_install_commands() {
    echo "Useful commands:"
    if [ "$INIT_SYSTEM" = "systemd" ]; then
        echo "  systemctl status ${SERVICE_NAME}    # Check status"
        echo "  journalctl -u ${SERVICE_NAME} -f    # View logs"
        echo "  systemctl restart ${SERVICE_NAME}   # Restart"
    else
        # helixscreen.init writes to /var/log/helixscreen/launcher.log when /var/log
        # is persistent, else ${INSTALL_DIR}/logs/launcher.log — show whichever exists.
        local log_path="/var/log/helixscreen/launcher.log"
        [ -f "$log_path" ] || log_path="${INSTALL_DIR}/logs/launcher.log"
        echo "  ${INIT_SCRIPT_DEST} status   # Check status"
        echo "  tail -f ${log_path}   # View logs"
        echo "  ${INIT_SCRIPT_DEST} restart  # Restart"
    fi
}

# ============================================
# Module: platform.sh
# ============================================

#
# Default paths (may be overridden by set_install_paths)
: "${INSTALL_DIR:=/opt/helixscreen}"
: "${TMP_DIR:=}"

# Capture user-provided INSTALL_DIR before we potentially override it.
# If the user explicitly set INSTALL_DIR (and it's not the default),
# we respect their choice over auto-detection.
_USER_INSTALL_DIR="${INSTALL_DIR}"
[ "$_USER_INSTALL_DIR" = "/opt/helixscreen" ] && _USER_INSTALL_DIR=""
INIT_SCRIPT_DEST=""
PREVIOUS_UI_SCRIPT=""
AD5M_FIRMWARE=""
K1_FIRMWARE=""
KLIPPER_USER=""
KLIPPER_GROUP=""
KLIPPER_HOME=""

# Friendly description of the underlying SBC for the user-facing log line.
# Returns free-text (NOT used for routing). Pi/pi32 covers a long tail of
# aarch64/armv7l Klipper boxes (Raspberry Pi, BTT CB1, MKS-Pi, QIDI Q2/Plus,
# generic Armbian) — they all run the same binary, but "Detected: pi" reads
# as wrong to anyone whose printer says QIDI on the lid. This emits a label
# based on /proc/device-tree/model, hostname, and home-directory shape so
# the user sees their own hardware reflected back.
describe_hardware() {
    local _model="" _hostname="" _pretty=""

    if [ -r /proc/device-tree/model ]; then
        _model=$(tr -d '\0' </proc/device-tree/model 2>/dev/null)
    fi
    if [ -r /etc/hostname ]; then
        _hostname=$(cat /etc/hostname 2>/dev/null | tr -d '[:space:]')
    fi
    if [ -r /etc/os-release ]; then
        # shellcheck disable=SC1091
        _pretty=$(. /etc/os-release 2>/dev/null && echo "${PRETTY_NAME:-${NAME:-}}")
    fi

    # Device-tree model is the strongest signal when present.
    case "$_model" in
        *"Raspberry Pi"*) echo "$_model"; return ;;
        *"BIGTREETECH"*|*"BTT"*) echo "BIGTREETECH SBC ($_model)"; return ;;
        *Rockchip*|*"RK3"*|*Allwinner*|*Amlogic*) ;;  # fall through, often too generic alone
    esac

    # Hostname + user-dir heuristics for boards without a useful DT model.
    # `linaro-alip` is the Linaro Debian reference rootfs hostname; QIDI
    # ships it on the Q2 (and likely Plus 4) running Klipper as `mks`.
    if [ "$_hostname" = "linaro-alip" ] && [ -d "/home/mks" ]; then
        echo "QIDI-class SBC (likely Q2/Plus, hostname: $_hostname, user: mks)"
        return
    fi
    if [ -d "/home/biqu" ]; then
        echo "BIGTREETECH Pi/CB1 (user: biqu)"
        return
    fi
    if [ -d "/home/mks" ]; then
        echo "MKS-branded SBC (user: mks)"
        return
    fi
    if [ -d "/home/pi" ] && [ -z "$_model" ]; then
        echo "Raspberry Pi (user: pi)"
        return
    fi

    if [ -n "$_model" ]; then
        echo "$_model"
        return
    fi
    if [ -n "$_pretty" ]; then
        echo "ARM SBC ($_pretty)"
        return
    fi
    echo "ARM SBC"
}

# Resolve the primary group of a user, falling back to the user name.
# Some firmwares (e.g. QIDI Q2 stock) ship a `mks` user without a matching
# `mks` group, which makes `Group=mks` in the systemd unit fail with
# "Failed to determine group credentials". Use `id -gn` to find the actual
# primary group; only fall back to the user name when getent fails.
_resolve_primary_group() {
    local _user="$1"
    [ -n "$_user" ] || { echo "root"; return; }
    local _g
    _g=$(id -gn "$_user" 2>/dev/null) || _g=""
    if [ -n "$_g" ]; then
        echo "$_g"
    else
        echo "$_user"
    fi
}

# Detect platform
# Returns: "ad5m", "ad5x", "cc1", "k1", "k2", "pi", "pi32", "snapmaker-u1", "x86", or "unsupported"
detect_platform() {
    local arch kernel
    arch=$(uname -m)
    kernel=$(uname -r)

    # Check for Elegoo Centauri Carbon running OpenCentauri COSMOS firmware.
    # MUST come before AD5M check — both are armv7l with kernel 5.4.61.
    # COSMOS replaces the stock Tina/OpenWrt userland with a Yocto-based rootfs
    # that ships Klipper, Moonraker, and its own update tool.
    if [ "$arch" = "armv7l" ] && [ -x "/usr/bin/update-cosmos" ]; then
        echo "cc1"
        return
    fi

    # Check for Creality K2 series (armv7l, OpenWrt/Tina Linux, /mnt/UDISK)
    # MUST come before AD5M check — both are armv7l with kernel 5.4.61
    if [ "$arch" = "armv7l" ] && [ -d "/mnt/UDISK" ]; then
        # K2 runs Tina Linux (OpenWrt-based) with storage on /mnt/UDISK
        if [ -f /etc/os-release ] && grep -qi "openwrt\|tina" /etc/os-release 2>/dev/null; then
            echo "k2"
            return
        fi
        # Fallback: /mnt/UDISK/printer_data is a strong K2 indicator even without os-release
        if [ -d "/mnt/UDISK/printer_data" ] || [ -d "/mnt/UDISK/creality" ]; then
            echo "k2"
            return
        fi
    fi

    # Check for AD5M (armv7l with specific kernel, NOT K2)
    if [ "$arch" = "armv7l" ]; then
        # AD5M has a specific kernel identifier
        if echo "$kernel" | grep -q "ad5m\|5.4.61"; then
            echo "ad5m"
            return
        fi
    fi

    # Check for FlashForge AD5X (MIPS with /usr/data and FlashForge indicators)
    # AD5X uses Ingenic X2600 (MIPS); identified by /usr/prog/ dir or /ZMOD file alongside /usr/data/
    if [ "$arch" = "mips" ]; then
        if [ -d "/usr/data" ] && { [ -d "/usr/prog" ] || [ -f "/ZMOD" ]; }; then
            echo "ad5x"
            return
        fi
    fi

    # Check for Creality K1 series (Simple AF or stock with Klipper)
    # K1 uses buildroot and has /usr/data structure
    if [ -f /etc/os-release ] && grep -q "buildroot" /etc/os-release 2>/dev/null; then
        # Buildroot-based system - check for K1 indicators
        if [ -d "/usr/data" ]; then
            # Check for K1-specific indicators (require at least 2 for confidence)
            # - get_sn_mac.sh is a Creality-specific script
            # - /usr/data/pellcorp is Simple AF
            # - /usr/data/printer_data with klipper is a strong K1 indicator
            local k1_indicators=0
            [ -x "/usr/bin/get_sn_mac.sh" ] && k1_indicators=$((k1_indicators + 1))
            [ -d "/usr/data/pellcorp" ] && k1_indicators=$((k1_indicators + 1))
            [ -d "/usr/data/printer_data" ] && k1_indicators=$((k1_indicators + 1))
            [ -d "/usr/data/klipper" ] && k1_indicators=$((k1_indicators + 1))
            # Also check for Creality-specific paths
            [ -f "/usr/data/creality/userdata/config/system_config.json" ] && k1_indicators=$((k1_indicators + 1))

            if [ "$k1_indicators" -ge 2 ]; then
                echo "k1"
                return
            fi
        fi
    fi

    # Snapmaker U1 (aarch64 + extended firmware markers)
    # Must check BEFORE generic Pi/ARM SBC since U1 is also aarch64 Debian
    if [ "$arch" = "aarch64" ]; then
        local u1_markers=0
        [ -d "/home/lava" ] && u1_markers=$((u1_markers + 1))
        [ -d "/home/lava/printer_data" ] && u1_markers=$((u1_markers + 1))
        [ -x "/usr/bin/unisrv" ] && u1_markers=$((u1_markers + 1))
        [ -d "/oem" ] && u1_markers=$((u1_markers + 1))
        # Check for RK3562 SoC in device-tree
        if [ -f /proc/device-tree/compatible ] && grep -q "rockchip,rk3562" /proc/device-tree/compatible 2>/dev/null; then
            u1_markers=$((u1_markers + 1))
        fi
        if [ "$u1_markers" -ge 2 ]; then
            echo "snapmaker-u1"
            return 0
        fi
    fi

    # Check for Debian-family SBC (Raspberry Pi, MKS, BTT, Armbian, etc.)
    # Returns "pi" for 64-bit, "pi32" for 32-bit
    if [ "$arch" = "aarch64" ] || [ "$arch" = "armv7l" ]; then
        local is_arm_sbc=false

        # 1. os-release: check for Debian-family indicators
        #    ID_LIKE=debian appears in all derivatives (Ubuntu, Armbian, Raspbian, etc.)
        #    so grepping for "debian" alone catches most cases.
        if [ -f /etc/os-release ] && \
           grep -qi "debian\|raspbian\|ubuntu\|armbian" /etc/os-release 2>/dev/null; then
            is_arm_sbc=true
        fi

        # 2. Package manager: dpkg is the definitive Debian-family indicator.
        #    Catches any derivative not listed above.
        if [ "$is_arm_sbc" = false ] && command -v dpkg >/dev/null 2>&1; then
            is_arm_sbc=true
        fi

        # 3. Well-known SBC user home directories (MainsailOS, BTT Pi, MKS)
        if [ "$is_arm_sbc" = false ]; then
            if [ -d /home/pi ] || [ -d /home/mks ] || [ -d /home/biqu ]; then
                is_arm_sbc=true
            fi
        fi

        if [ "$is_arm_sbc" = true ]; then
            # Detect actual userspace bitness, not just kernel arch.
            # Many Pi systems run 64-bit kernel with 32-bit userspace,
            # which makes uname -m report aarch64 even though only
            # 32-bit binaries can execute.
            local userspace_bits
            userspace_bits=$(getconf LONG_BIT 2>/dev/null || echo "")
            if [ "$userspace_bits" = "64" ]; then
                echo "pi"
            elif [ "$userspace_bits" = "32" ]; then
                if [ "$arch" = "aarch64" ]; then
                    log_warn "64-bit kernel with 32-bit userspace detected — using pi32 build"
                fi
                echo "pi32"
            else
                # getconf unavailable — fall back to checking system binary
                if file /usr/bin/id 2>/dev/null | grep -q "64-bit"; then
                    echo "pi"
                elif file /usr/bin/id 2>/dev/null | grep -q "32-bit"; then
                    if [ "$arch" = "aarch64" ]; then
                        log_warn "64-bit kernel with 32-bit userspace detected — using pi32 build"
                    fi
                    echo "pi32"
                else
                    # Last resort: trust kernel arch
                    if [ "$arch" = "aarch64" ]; then
                        echo "pi"
                    else
                        echo "pi32"
                    fi
                fi
            fi
            return
        fi
    fi

    # Check for x86_64 Linux (generic Debian/Ubuntu desktop or server)
    if [ "$arch" = "x86_64" ] || [ "$arch" = "i686" ] || [ "$arch" = "amd64" ]; then
        echo "x86"
        return
    fi

    # Unknown ARM device - don't assume it's a Pi
    # Require explicit platform indicators to avoid false positives
    if [ "$arch" = "aarch64" ] || [ "$arch" = "armv7l" ]; then
        log_warn "Unknown ARM platform. Cannot auto-detect."
        echo "unsupported"
        return
    fi

    echo "unsupported"
}

# AD5X (FlashForge / ZMOD) preflight: refuse to run outside the chroot.
#
# ZMOD installs HelixScreen into an overlay rooted at /usr/data/.mod/.zmod/.
# Inside the chroot the rootfs is the overlay (/, /etc, /opt, /srv all live
# under that overlay). Outside, those same paths point at the squashfs base
# view that helix-screen never sees — so a curl|sh, --local, --update, or
# --uninstall run from a fresh SSH session writes to the wrong filesystem
# entirely. The `/usr/data/.mod/.zmod` directory is only visible from outside
# the chroot, so its presence is the reliable "you forgot to chroot" tell.
#
# Aborts with an actionable message when called outside the chroot.
ad5x_check_chroot_context() {
    [ -d "/usr/data/.mod/.zmod" ] || return 0

    log_error ""
    log_error "=========================================================="
    log_error " AD5X manual installs must run inside the ZMOD chroot."
    log_error "=========================================================="
    log_error ""
    log_error "ZMOD installs HelixScreen into an overlay at:"
    log_error "  /usr/data/.mod/.zmod/"
    log_error ""
    log_error "Running this installer from your default SSH shell writes"
    log_error "into the squashfs base view, not the overlay HelixScreen"
    log_error "actually runs out of. That leaves you with broken paths,"
    log_error "no init script in scope, and a printer that boots into"
    log_error "the stock UI."
    log_error ""
    log_error "Enter the chroot first, then re-run your command:"
    log_error ""
    log_error "  chroot /usr/data/.mod/.zmod"
    log_error "  # then re-run: curl ... | sh   OR   sh install.sh --local <zip>"
    log_error "  # OR:          sh install.sh --update / --uninstall"
    log_error ""
    log_error "ZMOD also manages routine updates through Moonraker's update"
    log_error "manager — you only need this manual path for --local installs,"
    log_error "specific versions, or troubleshooting."
    log_error ""
    exit 1
}

# Detect the Klipper ecosystem user (who runs klipper/moonraker services)
# Detection cascade (most reliable first):
#   1. systemd: systemctl show klipper.service
#   2. Process table: ps for running klipper
#   3. printer_data scan: /home/*/printer_data
#   4. Well-known users: biqu, pi, mks
#   5. Fallback: root
# Sets: KLIPPER_USER, KLIPPER_HOME
detect_klipper_user() {
    # 1. systemd service owner (most reliable on Pi)
    if command -v systemctl >/dev/null 2>&1; then
        local svc_user
        svc_user=$(systemctl show -p User --value klipper.service 2>/dev/null) || true
        if [ -n "$svc_user" ] && [ "$svc_user" != "root" ] && id "$svc_user" >/dev/null 2>&1; then
            KLIPPER_USER="$svc_user"
            KLIPPER_GROUP=$(_resolve_primary_group "$svc_user")
            KLIPPER_HOME=$(eval echo "~$svc_user")
            log_info "Klipper user (systemd): $KLIPPER_USER (group: $KLIPPER_GROUP)"
            return 0
        fi
    fi

    # 2. Process table (catches running instances)
    local ps_user
    ps_user=$(ps -eo user,comm 2>/dev/null | awk '/klipper$/ && !/grep/ {print $1; exit}') || true
    if [ -n "$ps_user" ] && [ "$ps_user" != "root" ] && id "$ps_user" >/dev/null 2>&1; then
        KLIPPER_USER="$ps_user"
        KLIPPER_GROUP=$(_resolve_primary_group "$ps_user")
        KLIPPER_HOME=$(eval echo "~$ps_user")
        log_info "Klipper user (process): $KLIPPER_USER (group: $KLIPPER_GROUP)"
        return 0
    fi

    # 3. printer_data directory scan
    local pd_dir
    for pd_dir in /home/*/printer_data; do
        [ -d "$pd_dir" ] || continue
        local pd_user
        pd_user=$(echo "$pd_dir" | sed 's|^/home/||;s|/printer_data$||')
        if [ -n "$pd_user" ] && id "$pd_user" >/dev/null 2>&1; then
            KLIPPER_USER="$pd_user"
            KLIPPER_GROUP=$(_resolve_primary_group "$pd_user")
            KLIPPER_HOME="/home/$pd_user"
            log_info "Klipper user (printer_data): $KLIPPER_USER (group: $KLIPPER_GROUP)"
            return 0
        fi
    done

    # 4. Well-known users (checked in priority order)
    local known_user
    for known_user in biqu pi mks; do
        if id "$known_user" >/dev/null 2>&1; then
            KLIPPER_USER="$known_user"
            KLIPPER_GROUP=$(_resolve_primary_group "$known_user")
            KLIPPER_HOME="/home/$known_user"
            log_info "Klipper user (well-known): $KLIPPER_USER (group: $KLIPPER_GROUP)"
            return 0
        fi
    done

    # 5. Fallback: root (embedded platforms, AD5M, K1)
    KLIPPER_USER="root"
    KLIPPER_GROUP="root"
    KLIPPER_HOME="/root"
    log_info "Klipper user (fallback): root"
    return 0
}

# Detect AD5M firmware variant (Klipper Mod vs Forge-X vs ZMOD)
# Only called when platform is "ad5m"
# Returns: "klipper_mod", "forge_x", or "zmod"
detect_ad5m_firmware() {
    # ZMOD indicator - check for /ZMOD marker file
    # ZMOD is used on AD5M, AD5M Pro, and AD5X (FlashForge series)
    if [ -f "/ZMOD" ]; then
        echo "zmod"
        return
    fi

    # Klipper Mod indicators - check for its specific directory structure
    # Klipper Mod runs in a chroot on /mnt/data/.klipper_mod/chroot
    # v00.05: printer software in /root/printer_software/
    # v00.06+: printer software in /opt/ (no /root/printer_software)
    if [ -d "/root/printer_software" ] || [ -d "/mnt/data/.klipper_mod" ]; then
        echo "klipper_mod"
        return
    fi

    # Forge-X indicators - check for its mod overlay structure
    if [ -d "/opt/config/mod/.root" ]; then
        echo "forge_x"
        return
    fi

    # Default to forge_x (original behavior, most common)
    echo "forge_x"
}

# Detect K1 firmware variant (Simple AF, Guilouz helper-script, or stock)
# Only called when platform is "k1"
# Returns: "simple_af", "guilouz", or "stock_klipper"
detect_k1_firmware() {
    # Simple AF (pellcorp/creality) indicators
    if [ -d "/usr/data/pellcorp" ]; then
        echo "simple_af"
        return
    fi

    # Check for GuppyScreen which Simple AF installs
    if [ -d "/usr/data/guppyscreen" ] && [ -f "/etc/init.d/S99guppyscreen" ]; then
        echo "simple_af"
        return
    fi

    # Guilouz Helper Script (community firmware mod for K1 series)
    if [ -d "/usr/data/helper-script" ]; then
        echo "guilouz"
        return
    fi

    # Default to stock_klipper (generic K1 with Klipper)
    echo "stock_klipper"
}

# Detect Pi install directory based on Klipper ecosystem presence
# Cascade (first match wins):
#   1. User explicitly set INSTALL_DIR → keep it
#   2. ~/klipper or ~/moonraker exists → ~/helixscreen
#   3. ~/printer_data exists → ~/helixscreen
#   4. moonraker.service is active → ~/helixscreen
#   5. Fallback → /opt/helixscreen
# Requires: KLIPPER_HOME to be set (by detect_klipper_user)
# Sets: INSTALL_DIR
detect_pi_install_dir() {
    # 1. User explicitly set INSTALL_DIR — respect their choice
    if [ -n "$_USER_INSTALL_DIR" ]; then
        INSTALL_DIR="$_USER_INSTALL_DIR"
        log_info "Install directory (user override): $INSTALL_DIR"
        return 0
    fi

    # Need KLIPPER_HOME for ecosystem detection
    if [ -z "$KLIPPER_HOME" ]; then
        INSTALL_DIR="/opt/helixscreen"
        return 0
    fi

    # 2. Klipper or Moonraker source directories
    if [ -d "$KLIPPER_HOME/klipper" ] || [ -d "$KLIPPER_HOME/moonraker" ]; then
        INSTALL_DIR="$KLIPPER_HOME/helixscreen"
        log_info "Install directory (klipper ecosystem): $INSTALL_DIR"
        return 0
    fi

    # 3. printer_data directory (Klipper config structure)
    if [ -d "$KLIPPER_HOME/printer_data" ]; then
        INSTALL_DIR="$KLIPPER_HOME/helixscreen"
        log_info "Install directory (printer_data): $INSTALL_DIR"
        return 0
    fi

    # 4. Moonraker service running (ecosystem present but maybe different layout)
    if command -v systemctl >/dev/null 2>&1; then
        if systemctl is-active --quiet moonraker.service 2>/dev/null || \
           systemctl is-active --quiet moonraker 2>/dev/null; then
            INSTALL_DIR="$KLIPPER_HOME/helixscreen"
            log_info "Install directory (moonraker service): $INSTALL_DIR"
            return 0
        fi
    fi

    # 5. Fallback: no ecosystem detected
    INSTALL_DIR="/opt/helixscreen"
    return 0
}

# Detect best temp directory for extraction
# Mirrors get_helix_cache_dir() heuristic from app_globals.cpp:
# tries candidates in order, picks first writable dir with >= 100MB free.
# User can override via TMP_DIR env var.
# Sets: TMP_DIR
detect_tmp_dir() {
    # User already set TMP_DIR — respect it
    if [ -n "${TMP_DIR:-}" ]; then
        log_info "Temp directory (user override): $TMP_DIR"
        return 0
    fi

    local required_mb=100
    # /user-resource is CC1's large writable partition (4GB+); /data is tiny (~118MB)
    # and often too full once the tarball is downloaded there, so list /user-resource
    # ahead of the smaller candidates.
    local candidates="/user-resource/helixscreen-install /data/helixscreen-install /mnt/data/helixscreen-install /usr/data/helixscreen-install /var/tmp/helixscreen-install /tmp/helixscreen-install"

    for candidate in $candidates; do
        local check_dir
        check_dir=$(dirname "$candidate")

        # Must exist (or be creatable) and be writable
        if [ ! -d "$check_dir" ]; then
            continue
        fi
        if [ ! -w "$check_dir" ] && ! $SUDO test -w "$check_dir" 2>/dev/null; then
            continue
        fi

        # Check free space (BusyBox df: KB in $4)
        local available_mb
        available_mb=$(df "$check_dir" 2>/dev/null | tail -1 | awk '{print int($4/1024)}')
        if [ -z "$available_mb" ] || [ "$available_mb" -lt "$required_mb" ]; then
            continue
        fi

        TMP_DIR="$candidate"
        if [ "$check_dir" != "/tmp" ]; then
            log_info "Temp directory: $TMP_DIR (${available_mb}MB free)"
        fi
        return 0
    done

    # Last resort — /tmp even if small (will fail later at extraction with a clear error)
    TMP_DIR="/tmp/helixscreen-install"
    log_warn "No temp directory with ${required_mb}MB+ free found, using /tmp"
}

# Set installation paths based on platform and firmware
# Sets: INSTALL_DIR, INIT_SCRIPT_DEST, PREVIOUS_UI_SCRIPT, TMP_DIR
set_install_paths() {
    local platform=$1
    local firmware=${2:-}

    if [ "$platform" = "ad5m" ]; then
        # AD5M runs the helix-screen service as root on all three firmwares
        # (klipper_mod, zmod, forge_x). Pin KLIPPER_USER/HOME explicitly so
        # clean_helix_state_dirs and any other consumer don't fall back to
        # the empty default and silently skip the user-home sweep.
        KLIPPER_USER="root"
        KLIPPER_GROUP="root"
        KLIPPER_HOME="/root"
        case "$firmware" in
            klipper_mod)
                # v00.05 and earlier: /root/printer_software/helixscreen
                # v00.06+: /opt/helixscreen (no /root/printer_software dir)
                if [ -d "/root/printer_software" ]; then
                    INSTALL_DIR="/root/printer_software/helixscreen"
                else
                    INSTALL_DIR="/opt/helixscreen"
                fi
                INIT_SCRIPT_DEST="/etc/init.d/S80helixscreen"
                PREVIOUS_UI_SCRIPT="/etc/init.d/S80klipperscreen"
                log_info "AD5M firmware: Klipper Mod"
                log_info "Install directory: ${INSTALL_DIR}"
                ;;
            zmod)
                INSTALL_DIR="/srv/helixscreen"
                INIT_SCRIPT_DEST="/etc/init.d/S80helixscreen"
                PREVIOUS_UI_SCRIPT=""
                log_info "AD5M firmware: ZMOD"
                log_info "Install directory: ${INSTALL_DIR}"
                ;;
            forge_x|*)
                INSTALL_DIR="/opt/helixscreen"
                INIT_SCRIPT_DEST="/etc/init.d/S90helixscreen"
                PREVIOUS_UI_SCRIPT="/opt/config/mod/.root/S80guppyscreen"
                log_info "AD5M firmware: Forge-X"
                log_info "Install directory: ${INSTALL_DIR}"
                ;;
        esac
    elif [ "$platform" = "ad5x" ]; then
        # FlashForge AD5X - uses ZMOD, /usr/data structure, runs as root
        KLIPPER_USER="root"
        KLIPPER_GROUP="root"
        KLIPPER_HOME="/root"
        INSTALL_DIR="/srv/helixscreen"
        INIT_SCRIPT_DEST="/etc/init.d/S80helixscreen"
        PREVIOUS_UI_SCRIPT=""
        log_info "Platform: FlashForge AD5X (ZMOD)"
        log_info "Install directory: ${INSTALL_DIR}"
    elif [ "$platform" = "k1" ]; then
        # Creality K1 series - uses /usr/data structure.
        # printer_data is at /usr/data/printer_data (squashfs /root is RO).
        # Without the explicit override, detect_klipper_user falls back to
        # KLIPPER_HOME=/root and setup_config_symlink skips with
        # "No printer_data/config found" on every K1 install.
        INSTALL_DIR="/usr/data/helixscreen"
        INIT_SCRIPT_DEST="/etc/init.d/S99helixscreen"
        KLIPPER_USER="root"
        KLIPPER_GROUP="root"
        KLIPPER_HOME="/usr/data"
        case "$firmware" in
            simple_af)
                PREVIOUS_UI_SCRIPT="/etc/init.d/S99guppyscreen"
                log_info "K1 firmware: Simple AF"
                ;;
            guilouz)
                PREVIOUS_UI_SCRIPT=""
                log_info "K1 firmware: Guilouz Helper Script"
                ;;
            stock_klipper|*)
                PREVIOUS_UI_SCRIPT=""
                log_info "K1 firmware: Stock Klipper"
                ;;
        esac
        log_info "Install directory: ${INSTALL_DIR}"
    elif [ "$platform" = "k2" ]; then
        # Creality K2 series - OpenWrt/Tina Linux, storage on /mnt/UDISK.
        # printer_data lives on /mnt/UDISK (squashfs /root has no space).
        # Some K2 bootstrap projects (k2-improvements) drop a symlink
        # /root/printer_data -> /mnt/UDISK/printer_data/, but the installer
        # runs before that bootstrap for many users — point KLIPPER_HOME at
        # the actual storage so config symlinks work on first install.
        INSTALL_DIR="/opt/helixscreen"
        INIT_SCRIPT_DEST="/etc/init.d/S99helixscreen"
        PREVIOUS_UI_SCRIPT=""
        KLIPPER_USER="root"
        KLIPPER_GROUP="root"
        KLIPPER_HOME="/mnt/UDISK"
        log_info "Platform: Creality K2 series"
        log_info "Install directory: ${INSTALL_DIR}"
    elif [ "$platform" = "cc1" ]; then
        # Elegoo Centauri Carbon running OpenCentauri COSMOS.
        # - / is read-only squashfs; /etc is an overlay on /data (writable).
        # - /user-resource is the 6.3 GB ext4 partition where user installs go.
        # - COSMOS provides gui-switcher: drop /etc/init.d/<name>, then
        #   `config-manager ui screen_ui <name>` + restart gui-switcher.
        INSTALL_DIR="/user-resource/helixscreen"
        INIT_SCRIPT_DEST="/etc/init.d/helixscreen"
        PREVIOUS_UI_SCRIPT=""
        KLIPPER_USER="root"
        KLIPPER_GROUP="root"
        KLIPPER_HOME="/root"
        INIT_SYSTEM="sysv"
        log_info "Platform: Elegoo Centauri Carbon (COSMOS)"
        log_info "Install directory: ${INSTALL_DIR}"
    elif [ "$platform" = "snapmaker-u1" ]; then
        # Snapmaker U1: klipper runs as user 'lava', printer_data lives at
        # /home/lava/printer_data. HelixScreen itself runs as root, but
        # config symlinks must target the lava-owned tree so Mainsail/Fluidd
        # can read them. detect_klipper_user normally finds /home/lava, but
        # on a freshly-flashed U1 before klipper has ever run that path may
        # not exist yet — make it explicit so the installer is deterministic.
        INSTALL_DIR="/userdata/helixscreen"
        KLIPPER_USER="root"
        KLIPPER_GROUP="root"
        KLIPPER_HOME="/home/lava"
        INIT_SYSTEM="sysv"
        # U1 does NOT install /etc/init.d/S99helixscreen. install_service_snapmaker_u1
        # patches the stock /etc/init.d/S99screen to delegate to helixscreen.init for
        # start|stop|restart only (no `status`). Point INIT_SCRIPT_DEST at the real,
        # full-featured init script so post-install commands and stop_service work.
        INIT_SCRIPT_DEST="${INSTALL_DIR}/config/helixscreen.init"
        log_info "Platform: Snapmaker U1"
        log_info "Install directory: ${INSTALL_DIR}"
    else
        # Pi and other platforms — detect klipper user, then auto-detect install dir
        INIT_SCRIPT_DEST="/etc/init.d/S90helixscreen"
        PREVIOUS_UI_SCRIPT=""
        detect_klipper_user
        detect_pi_install_dir
    fi

    # Auto-detect best temp directory (all platforms)
    detect_tmp_dir
}

# User-editable config files that live in printer_data/config/helixscreen/.
# These are the files users may want to edit from Fluidd/Mainsail, and that
# the app writes to at runtime. All other files in INSTALL_DIR/config/ are
# static assets reinstalled on each update.
HELIX_USER_CONFIG_FILES="settings.json helixscreen.env .disabled_services tool_spools.json"

# Set up editable config directory in printer_data/config/helixscreen/.
#
# Creates a real directory (not a symlink) in printer_data/config/helixscreen/
# and symlinks user-editable files FROM the install dir INTO printer_data.
# This reverses the old approach (directory symlink into install dir) which
# was blocked by Moonraker's update_manager reserved path protection.
#
# Layout after setup:
#   ~/printer_data/config/helixscreen/           (real directory)
#   ~/printer_data/config/helixscreen/settings.json     (real file)
#   ~/helixscreen/config/settings.json → above          (symlink)
#
# On upgrade from old layout, migrates files from install dir to printer_data.
# Reads: KLIPPER_HOME, INSTALL_DIR
setup_config_symlink() {
    # Only proceed if we have a Klipper home and install directory
    if [ -z "${KLIPPER_HOME:-}" ] || [ -z "${INSTALL_DIR:-}" ]; then
        return 0
    fi

    local pd_config="${KLIPPER_HOME}/printer_data/config"
    local pd_helix="${pd_config}/helixscreen"
    local install_config="${INSTALL_DIR}/config"

    # Skip if printer_data/config doesn't exist
    if [ ! -d "$pd_config" ]; then
        log_info "No printer_data/config found, skipping config symlink"
        return 0
    fi

    # Skip if install config directory doesn't exist
    if [ ! -d "$install_config" ]; then
        log_warn "Install config directory not found: $install_config"
        return 0
    fi

    # --- Migrate from old layout (directory symlink) ---
    if [ -L "$pd_helix" ]; then
        log_info "Migrating from old config symlink layout..."
        local old_target
        old_target=$(readlink "$pd_helix" 2>/dev/null || echo "")
        $(file_sudo "$pd_helix") rm -f "$pd_helix"
        log_info "Removed old directory symlink (was: $old_target)"
    fi

    # --- Create printer_data/config/helixscreen/ directory ---
    if [ ! -d "$pd_helix" ]; then
        if $(file_sudo "$pd_config") mkdir -p "$pd_helix" 2>/dev/null; then
            log_info "Created $pd_helix"
        else
            log_warn "Could not create $pd_helix (permission denied?)"
            return 0
        fi
    fi

    # --- Migrate helixconfig.json → settings.json in printer_data if needed ---
    if [ -f "${pd_helix}/helixconfig.json" ] && [ ! -f "${pd_helix}/settings.json" ]; then
        $(file_sudo "$pd_helix") mv "${pd_helix}/helixconfig.json" "${pd_helix}/settings.json"
        log_info "Migrated printer_data config: helixconfig.json → settings.json"
    fi
    # Remove old symlink if it exists (new one will be created by HELIX_USER_CONFIG_FILES loop)
    if [ -L "${install_config}/helixconfig.json" ]; then
        $(file_sudo "$install_config") rm "${install_config}/helixconfig.json"
        log_info "Removed old helixconfig.json symlink"
    fi

    # --- Set up per-file symlinks ---
    local file
    for file in $HELIX_USER_CONFIG_FILES; do
        local pd_file="${pd_helix}/${file}"
        local install_file="${install_config}/${file}"

        # If the install dir has a real file (not a symlink), move it to printer_data
        if [ -f "$install_file" ] && [ ! -L "$install_file" ]; then
            if [ ! -f "$pd_file" ]; then
                # Move the file to printer_data — check for success before removing original.
                # A silent cp failure followed by rm would permanently destroy the user's config.
                if $(file_sudo "$pd_helix") cp "$install_file" "$pd_file" 2>/dev/null; then
                    log_info "Migrated $file to printer_data"
                else
                    log_warn "Could not migrate $file to printer_data — keeping in install dir"
                    continue  # Skip symlink creation; leave the real file in place
                fi
            fi
            # Remove the original so we can create the symlink
            $(file_sudo "$install_config") rm -f "$install_file" 2>/dev/null
        fi

        # If pd_file still doesn't exist (e.g. runtime-created file like tool_spools.json
        # or .disabled_services that isn't packaged and hasn't been written yet), skip
        # symlink creation.  A dangling symlink is worse than no symlink: reads return
        # ENOENT and writes may fail depending on the OS/filesystem.  The app will
        # create the file at pd_file naturally; setup_config_symlink will wire it up
        # correctly on the next update or reinstall.
        if [ ! -f "$pd_file" ] && [ ! -L "$pd_file" ]; then
            # Only skip if install_file also doesn't exist or isn't already a symlink
            if [ ! -L "$install_file" ]; then
                continue
            fi
        fi

        # Create symlink: install_dir/config/file → printer_data/config/helixscreen/file
        if [ -L "$install_file" ]; then
            local current_target
            current_target=$(readlink "$install_file" 2>/dev/null || echo "")
            if [ "$current_target" = "$pd_file" ]; then
                continue  # Already correct
            fi
            $(file_sudo "$install_config") rm -f "$install_file" 2>/dev/null
        fi

        if $(file_sudo "$install_config") ln -s "$pd_file" "$install_file" 2>/dev/null; then
            : # Symlink created
        else
            log_warn "Could not create symlink for $file"
        fi
    done

    log_success "Config directory: $pd_helix"
    log_info "You can now edit HelixScreen config from Mainsail/Fluidd"
    return 0
}

# Remove config symlinks and optionally the printer_data directory.
# Called during uninstall. Preserves user files in printer_data.
# Reads: KLIPPER_HOME, INSTALL_DIR
remove_config_symlink() {
    if [ -z "${KLIPPER_HOME:-}" ] || [ -z "${INSTALL_DIR:-}" ]; then
        return 0
    fi

    local pd_helix="${KLIPPER_HOME}/printer_data/config/helixscreen"
    local install_config="${INSTALL_DIR}/config"

    # Remove per-file symlinks from install dir
    local file
    for file in $HELIX_USER_CONFIG_FILES; do
        local install_file="${install_config}/${file}"
        if [ -L "$install_file" ]; then
            rm -f "$install_file" 2>/dev/null
        fi
    done

    # Remove old-style directory symlink if present
    if [ -L "$pd_helix" ]; then
        rm -f "$pd_helix" 2>/dev/null
        log_info "Removed old config directory symlink"
    fi

    # Leave printer_data/config/helixscreen/ directory intact — user's config files
    if [ -d "$pd_helix" ]; then
        log_info "User config preserved at: $pd_helix"
    fi

    return 0
}

# Fix known Klipper config issues on AD5M KlipperMod printers.
# The AD5M ships with screw_thread: CW-M4 but the correct value is CCW-M4.
# This causes SCREWS_TILT_CALCULATE to output inverted CW/CCW directions,
# leading users to tighten when they should loosen (and vice versa).
# Only applies to KlipperMod (Forge-X and ZMOD don't ship screws_tilt_adjust).
fix_ad5m_klipper_config() {
    # Guard: only run on AD5M KlipperMod (uses lowercase $platform from main())
    if [ "${platform:-}" != "ad5m" ] || [ "${AD5M_FIRMWARE:-}" != "klipper_mod" ]; then
        return 0
    fi

    log_info "Checking AD5M Klipper config for known issues..."

    local config_dir="${KLIPPER_HOME}/printer_data/config"
    if [ ! -d "$config_dir" ]; then
        log_info "No printer_data/config found, skipping Klipper config fixup"
        return 0
    fi

    # Find config file with screws_tilt_adjust containing exactly "CW-M4"
    # (not "CCW-M4" — grep -w ensures word boundary so CW-M4 won't match CCW-M4)
    local target_file=""
    for cfg_file in "$config_dir"/printer.base.cfg "$config_dir"/printer.cfg; do
        [ -f "$cfg_file" ] || continue
        if grep -q '\[screws_tilt_adjust\]' "$cfg_file" && \
           grep -qw 'CW-M4' "$cfg_file" && \
           ! grep -qw 'CCW-M4' "$cfg_file"; then
            target_file="$cfg_file"
            break
        fi
    done

    if [ -z "$target_file" ]; then
        log_info "AD5M screw_thread config OK (or not present)"
        return 0
    fi

    log_info "Found incorrect screw_thread in: $target_file"
    log_info "  CW-M4 → CCW-M4 (AD5M bed screws need reverse direction)"

    # Backup before modifying
    local backup_file="${target_file}.pre-helix"
    if [ ! -f "$backup_file" ]; then
        $SUDO cp "$target_file" "$backup_file"
        log_info "  Backup: $backup_file"
    fi

    # Fix: replace exactly "CW-M4" with "CCW-M4" on screw_thread lines only.
    # Anchored on line start (^) and end ($) to prevent matching CCW-M4.
    # Uses temp file instead of sed -i for portability (macOS vs BusyBox).
    local tmp_file="${target_file}.tmp"
    $SUDO sed 's/^\(screw_thread:[[:space:]]*\)CW-M4$/\1CCW-M4/' "$target_file" > "$tmp_file"
    $SUDO mv "$tmp_file" "$target_file"

    if grep -qw 'CCW-M4' "$target_file"; then
        log_success "Fixed AD5M screw_thread: CW-M4 → CCW-M4"
    else
        log_warn "Failed to fix screw_thread, restoring backup"
        $SUDO cp "$backup_file" "$target_file"
        return 1
    fi

    return 0
}

# ============================================
# Module: permissions.sh
# ============================================

#
# Initialize SUDO (will be set by check_permissions)
SUDO=""
# Check if running as root (required for AD5M/K1, optional for Pi)
# Sets: SUDO variable ("sudo" or "")
check_permissions() {
    local platform=$1

    case "$platform" in
    ad5m|ad5x|k1|k2)
        if [ "$(id -u)" != "0" ]; then
            log_error "Installation on $platform requires root privileges."
            log_error "Please run: sudo $0 $*"
            exit 1
        fi
        SUDO=""
        ;;
    *)
        # Pi: warn if not root but allow sudo
        if [ "$(id -u)" != "0" ]; then
            if ! command -v sudo >/dev/null 2>&1; then
                log_error "Not running as root and sudo is not available."
                log_error "Please run as root or install sudo."
                exit 1
            fi
            log_info "Not running as root. Will use sudo for privileged operations."
            SUDO="sudo"
        else
            SUDO=""
        fi
        ;;
    esac
}

# Check if a polkit rule for HelixScreen exists (either .rules or .pkla)
_polkit_rule_exists() {
    local pkla="/etc/polkit-1/localauthority/50-local.d/helixscreen-network.pkla"
    local rules="/etc/polkit-1/rules.d/49-helixscreen-network.rules"
    local rules_old="/etc/polkit-1/rules.d/50-helixscreen-network.rules"

    test -f "$rules" 2>/dev/null && return 0
    test -f "$rules_old" 2>/dev/null && return 0
    test -f "$pkla" 2>/dev/null && return 0
    return 1
}

# Check if deployed permission rules contain un-substituted templates
_permission_rules_need_repair() {
    local helix_user="$1"
    local pkla="/etc/polkit-1/localauthority/50-local.d/helixscreen-network.pkla"
    local rules="/etc/polkit-1/rules.d/49-helixscreen-network.rules"

    # Check pkla file for literal placeholder (parent dir may be root-only)
    if $SUDO test -f "$pkla" && $SUDO grep -q '@@HELIX_USER@@' "$pkla" 2>/dev/null; then
        return 0
    fi
    # Check JS rules file for literal placeholder
    if $SUDO test -f "$rules" && $SUDO grep -q '@@HELIX_USER@@' "$rules" 2>/dev/null; then
        return 0
    fi
    return 1
}

# Install system permission rules for non-root operation
# - udev rule: backlight brightness write access for video group
# - polkit rule: NetworkManager access for service user
# Only installed on platforms that run as non-root (Pi, generic Linux)
install_permission_rules() {
    local platform=$1
    local helix_user="${KLIPPER_USER:-root}"

    # Skip for platforms that run as root or if user is root
    case "$platform" in ad5m|ad5x|k1|k2) helix_user="root" ;; esac
    if [ "$helix_user" = "root" ]; then
        log_info "Skipping permission rules (running as root)"
        return 0
    fi

    # Under NoNewPrivileges (self-update), sudo is blocked.  Check if rules
    # are already correctly deployed before skipping.
    if _has_no_new_privs; then
        if command -v nmcli >/dev/null 2>&1 && ! _polkit_rule_exists; then
            log_warn "NetworkManager polkit rule is MISSING — Wi-Fi will not work as non-root."
            log_warn "Fix by re-running the installer:  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
        elif _permission_rules_need_repair "$helix_user"; then
            log_warn "Permission rules need repair (pkla/polkit file has un-substituted template)."
            log_warn "Wi-Fi may not work. Fix with:  sudo sed -i 's|@@HELIX_USER@@|${helix_user}|g' /etc/polkit-1/localauthority/50-local.d/helixscreen-network.pkla"
            log_warn "Or re-run the installer:  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
        else
            log_info "Skipping permission rules (NoNewPrivileges; already installed)"
        fi
        return 0
    fi

    # --- Backlight udev rule ---
    local udev_src="${INSTALL_DIR}/config/99-helixscreen-backlight.rules"
    local udev_dest="/etc/udev/rules.d/99-helixscreen-backlight.rules"

    if [ -f "$udev_src" ] && [ -d /etc/udev/rules.d ]; then
        $SUDO cp "$udev_src" "$udev_dest"
        # Trigger udev to apply immediately for any existing backlight devices
        $SUDO udevadm trigger --subsystem-match=backlight 2>/dev/null || true
        log_info "Installed backlight udev rule"
    fi

    # --- NetworkManager polkit rule ---
    # All content is generated inline — no template files, no sed, no @@HELIX_USER@@.
    if command -v nmcli >/dev/null 2>&1; then
        # polkit JavaScript rules for newer polkit (Debian 12+, polkit >= 0.106)
        local rules_dir="/etc/polkit-1/rules.d"
        # polkit local authority (.pkla) for older polkit (Debian 11 and similar)
        local pkla_dir="/etc/polkit-1/localauthority/50-local.d"

        if $SUDO test -d "$rules_dir"; then
            local rules_dest="${rules_dir}/49-helixscreen-network.rules"
            if $SUDO tee "$rules_dest" > /dev/null << POLKIT_EOF
// Installed by HelixScreen — allow service user to manage NetworkManager
polkit.addRule(function(action, subject) {
    if (action.id.indexOf("org.freedesktop.NetworkManager.") === 0 &&
        subject.user === "${helix_user}") {
        return polkit.Result.YES;
    }
});
POLKIT_EOF
            then
                log_info "Installed NetworkManager polkit rule (.rules for ${helix_user})"
            else
                log_warn "Failed to install polkit rule to ${rules_dest} — Wi-Fi scanning may not work"
            fi
            # Clean up old 50- rule and stale .pkla from older installs / OS upgrades
            $SUDO rm -f "${rules_dir}/50-helixscreen-network.rules" 2>/dev/null || true
            local stale_pkla="${pkla_dir}/helixscreen-network.pkla"
            if $SUDO test -f "$stale_pkla" 2>/dev/null; then
                $SUDO rm -f "$stale_pkla" 2>/dev/null || true
                log_info "Removed stale .pkla file (superseded by .rules)"
            fi
        elif $SUDO test -d "$pkla_dir"; then
            local pkla_dest="${pkla_dir}/helixscreen-network.pkla"
            if $SUDO tee "$pkla_dest" > /dev/null << PKLA_EOF
# polkit local authority rule: allow HelixScreen service user to manage
# NetworkManager connections (Wi-Fi connect/disconnect/scan)
# Installed by HelixScreen for non-root service operation
[HelixScreen NetworkManager access]
Identity=unix-user:${helix_user}
Action=org.freedesktop.NetworkManager.*
ResultAny=yes
ResultInactive=yes
ResultActive=yes
PKLA_EOF
            then
                log_info "Installed NetworkManager polkit rule (.pkla for ${helix_user})"
            else
                log_warn "Failed to install polkit rule to ${pkla_dest} — Wi-Fi scanning may not work"
            fi
        else
            log_warn "polkit rules directory not found — Wi-Fi may not work as non-root"
        fi

        # Reload polkit to pick up the new rule immediately
        if systemctl is-active polkit >/dev/null 2>&1; then
            $SUDO systemctl restart polkit 2>/dev/null || true
            log_info "Restarted polkit to apply new rules"
        fi
    fi
}

# ============================================
# Module: requirements.sh
# ============================================

#
# Initialize INIT_SYSTEM (will be set by detect_init_system)
INIT_SYSTEM=""
# Run `apt-get update` at most once per installer run. The first call updates
# the package index; subsequent calls become no-ops. Avoids 5-15s of redundant
# index refreshes when both check_requirements and install_runtime_deps need apt.
_HELIX_APT_UPDATED=""
_apt_update_once() {
    [ -n "$_HELIX_APT_UPDATED" ] && return 0
    $SUDO apt-get update -qq 2>/dev/null || true
    _HELIX_APT_UPDATED=1
}

# Append a name to the global $missing list, comma-separated.
_helix_add_missing() { missing="${missing:+$missing, }$1"; }

# Check required commands exist. unzip is mandatory because release archives
# ship as .zip (Moonraker Update Manager contract); tar/gunzip remain required
# for bridge-release tar.gz fallback until 1.0 retires the format.
check_requirements() {
    local missing=""

    # Need either curl or wget
    if ! command -v curl >/dev/null 2>&1 && ! command -v wget >/dev/null 2>&1; then
        _helix_add_missing "curl or wget"
    fi
    command -v tar >/dev/null 2>&1 || _helix_add_missing "tar"
    # gunzip needed for AD5M BusyBox tar which doesn't support -z
    command -v gunzip >/dev/null 2>&1 || _helix_add_missing "gunzip"

    # Try transparent apt-install of unzip when missing — many minimal
    # Debian/Ubuntu images (notably Snapmaker U1 extended firmware) ship without it.
    if ! command -v unzip >/dev/null 2>&1; then
        if command -v apt-get >/dev/null 2>&1 && ! _has_no_new_privs; then
            log_info "Installing missing dependency: unzip"
            _apt_update_once
            $SUDO apt-get install -y --no-install-recommends unzip >/dev/null 2>&1 \
                || _helix_add_missing "unzip"
        else
            _helix_add_missing "unzip"
        fi
    fi

    if [ -n "$missing" ]; then
        log_error "Missing required commands: $missing"
        log_error "Please install them and try again."
        exit 1
    fi

    log_success "All required commands available"
}

# Install runtime dependencies for Pi platform
# Required for DRM display and evdev input handling
# AD5M uses framebuffer with static linking, no deps needed
install_runtime_deps() {
    local platform=$1

    # Only needed for Pi (32-bit and 64-bit) - AD5M uses framebuffer with static linking
    if [ "$platform" != "pi" ] && [ "$platform" != "pi32" ]; then
        return 0
    fi

    log_info "Checking runtime dependencies for display/input..."

    # Required libraries for DRM display, libinput, GPU rendering, and camera
    # GPU libs are needed for DRM+EGL hardware-accelerated rendering on Pi
    # libturbojpeg: SIMD-accelerated JPEG decode for camera MJPEG streams
    #   Debian names it libturbojpeg0, Ubuntu names it libturbojpeg
    # Note: OpenSSL is statically linked for Pi builds, no runtime libssl needed
    local deps="libdrm2 libinput10 libgbm1 libegl1 libgles2"
    local missing=""

    # turbojpeg: package name varies by distro (Debian=libturbojpeg0, Ubuntu=libturbojpeg)
    local turbo_pkg=""
    for candidate in libturbojpeg0 libturbojpeg; do
        if dpkg-query -W -f='${Status}' "$candidate" 2>/dev/null | grep -q "install ok installed" || \
           apt-cache show "$candidate" 2>/dev/null | grep -q "^Package:"; then
            turbo_pkg="$candidate"
            break
        fi
    done
    if [ -n "$turbo_pkg" ]; then
        deps="$deps $turbo_pkg"
    else
        log_warn "No turbojpeg package found (tried libturbojpeg0, libturbojpeg)"
        log_warn "JPEG thumbnail decoding may not work"
    fi

    for dep in $deps; do
        # Check if package is installed (dpkg-query returns 0 if installed)
        if ! dpkg-query -W -f='${Status}' "$dep" 2>/dev/null | grep -q "install ok installed"; then
            if [ -n "$missing" ]; then
                missing="$missing $dep"
            else
                missing="$dep"
            fi
        fi
    done

    if [ -n "$missing" ]; then
        # Under NoNewPrivileges (self-update from the running app), sudo is blocked.
        # Warn about missing deps but don't fail — the binary may still work, and
        # verify_binary_deps() will catch truly fatal missing libraries later.
        if _has_no_new_privs; then
            log_warn "Missing runtime libraries (cannot install under self-update): $missing"
            log_warn "Install manually after update: sudo apt-get install $missing"
            return 0
        fi
        log_info "Installing missing libraries: $missing"
        _apt_update_once
        # shellcheck disable=SC2086
        if ! $SUDO apt-get install -y --no-install-recommends $missing; then
            log_warn "Failed to install some runtime libraries: $missing"
            log_warn "The update will continue. Install manually: sudo apt-get install $missing"
        else
            log_success "Runtime libraries installed"
        fi
    else
        log_success "All runtime libraries already installed"
    fi
}

# Check available disk space
# Requires at least 50MB free on the install directory's filesystem
# Note: INSTALL_DIR must be set before calling this function
check_disk_space() {
    local platform=$1
    local required_mb=50

    # Get the parent directory of install location (the filesystem to check)
    local check_dir
    check_dir=$(dirname "${INSTALL_DIR:-/opt/helixscreen}")
    # Walk up until we find an existing directory
    while [ ! -d "$check_dir" ] && [ "$check_dir" != "/" ]; do
        check_dir=$(dirname "$check_dir")
    done
    if [ "$check_dir" = "/" ]; then
        check_dir="/"
    fi

    # Get available space in MB
    local available_mb
    case "$platform" in
        ad5m|ad5x|k1|k2)
            # BusyBox df: blocks are in KB by default
            available_mb=$(df "$check_dir" 2>/dev/null | tail -1 | awk '{print int($4/1024)}')
            ;;
        *)
            # GNU df with -m flag outputs in MB
            available_mb=$(df -m "$check_dir" 2>/dev/null | tail -1 | awk '{print $4}')
            ;;
    esac

    if [ -n "$available_mb" ] && [ "$available_mb" -lt "$required_mb" ]; then
        log_error "Insufficient disk space on $check_dir"
        log_error "Required: ${required_mb}MB, Available: ${available_mb}MB"
        exit 1
    fi

    log_info "Disk space check: ${available_mb}MB available on $check_dir"
}

# Detect init system (systemd vs SysV)
# Sets: INIT_SYSTEM to "systemd" or "sysv"
detect_init_system() {
    # Check for systemd
    if command -v systemctl >/dev/null 2>&1 && [ -d /run/systemd/system ]; then
        INIT_SYSTEM="systemd"
        log_info "Init system: systemd"
        return
    fi

    # Check for SysV init (BusyBox or traditional)
    if [ -d /etc/init.d ]; then
        INIT_SYSTEM="sysv"
        log_info "Init system: SysV (BusyBox/traditional)"
        return
    fi

    log_error "Could not detect init system."
    log_error "Neither systemd nor /etc/init.d found."
    exit 1
}

# Check that Klipper and Moonraker are running (AD5M + K1 only)
# These platforms require local Klipper/Moonraker; without them HelixScreen
# has nothing to connect to. Warns and prompts for confirmation.
check_klipper_ecosystem() {
    local platform=$1

    # Only relevant for embedded platforms with local Klipper
    case "$platform" in
        ad5m|ad5x|k1|k2) ;;
        *) return 0 ;;
    esac

    local warnings=""

    # Check Klipper process
    # Klipper runs as "klippy" (python module) or "klipper" (service name)
    if ! ps | grep -v grep | grep -q -e '[Kk]lipper' -e '[Kk]lippy'; then
        warnings="Klipper does not appear to be running."
    fi

    # Check Moonraker process
    if ! ps | grep -v grep | grep -q '[Mm]oonraker'; then
        if [ -n "$warnings" ]; then
            warnings="$warnings
Moonraker does not appear to be running."
        else
            warnings="Moonraker does not appear to be running."
        fi
    fi

    # If Moonraker process is up, verify it responds on the expected port
    if ps | grep -v grep | grep -q '[Mm]oonraker'; then
        if command -v wget >/dev/null 2>&1; then
            if ! wget -q -O /dev/null --timeout=5 "http://127.0.0.1:7125/server/info" 2>/dev/null; then
                if [ -n "$warnings" ]; then
                    warnings="$warnings
Moonraker is running but not responding on http://127.0.0.1:7125."
                else
                    warnings="Moonraker is running but not responding on http://127.0.0.1:7125."
                fi
            fi
        elif command -v curl >/dev/null 2>&1; then
            if ! curl -sf --connect-timeout 5 "http://127.0.0.1:7125/server/info" >/dev/null 2>&1; then
                if [ -n "$warnings" ]; then
                    warnings="$warnings
Moonraker is running but not responding on http://127.0.0.1:7125."
                else
                    warnings="Moonraker is running but not responding on http://127.0.0.1:7125."
                fi
            fi
        fi
    fi

    # Everything looks good
    if [ -z "$warnings" ]; then
        log_success "Klipper and Moonraker are running"
        return 0
    fi

    # Show warnings and prompt
    log_warn ""
    log_warn "WARNING: Klipper ecosystem check failed:"
    # Print each warning line separately
    echo "$warnings" | while IFS= read -r line; do
        log_warn "  - $line"
    done
    log_warn ""
    log_warn "HelixScreen requires Klipper and Moonraker to function."
    log_warn "It will install but won't work until these services are available."

    # Non-interactive mode: just warn and continue
    if [ ! -t 0 ]; then
        log_warn "Non-interactive mode: continuing anyway."
        return 0
    fi

    printf "Continue anyway? [y/N] "
    read -r answer
    case "$answer" in
        [Yy]|[Yy][Ee][Ss])
            log_info "Continuing installation..."
            return 0
            ;;
        *)
            log_error "Installation cancelled."
            exit 1
            ;;
    esac
}

# Verify the installed binary can find all shared libraries
# Runs ldd on the binary and checks for "not found" entries.
# If libssl.so.1.1 is missing (Bullseye→Bookworm upgrade), tries to install compat package.
# Called after extraction, before starting the service.
# Requires: INSTALL_DIR
verify_binary_deps() {
    local platform=$1
    local binary="${INSTALL_DIR}/bin/helix-screen"

    # Only relevant for platforms with dynamic linking and ldd
    if ! command -v ldd >/dev/null 2>&1; then
        return 0
    fi

    # Binary must exist
    if [ ! -f "$binary" ]; then
        log_warn "Binary not found at $binary, skipping dependency check"
        return 0
    fi

    # Check for missing shared libraries
    local missing_libs
    missing_libs=$(ldd "$binary" 2>/dev/null | grep "not found" || true)

    if [ -z "$missing_libs" ]; then
        log_success "All shared library dependencies satisfied"
        return 0
    fi

    log_warn "Missing shared libraries detected:"
    echo "$missing_libs" | while IFS= read -r line; do
        log_warn "  $line"
    done

    # Try to fix known issues on Pi
    case "$platform" in
        pi|pi32)
            # libssl.so.1.1 missing = Bookworm system with Bullseye-era binary
            if echo "$missing_libs" | grep -q "libssl.so.1.1"; then
                log_info "libssl.so.1.1 not found (common after Debian Bullseye→Bookworm upgrade)"
                # Try installing the compat package if available
                if apt-cache show libssl1.1 >/dev/null 2>&1; then
                    log_info "Installing libssl1.1 compatibility package..."
                    $SUDO apt-get install -y --no-install-recommends libssl1.1
                else
                    log_error "libssl1.1 package not available in your repositories."
                    log_error "This binary was built against OpenSSL 1.1 but your system has OpenSSL 3."
                    log_error "Please update HelixScreen to the latest version which includes OpenSSL statically."
                    exit 1
                fi
            fi

            # Re-check after attempted fixes
            missing_libs=$(ldd "$binary" 2>/dev/null | grep "not found" || true)
            if [ -n "$missing_libs" ]; then
                # Check if fbdev fallback binary exists and is loadable
                local fallback="${INSTALL_DIR}/bin/helix-screen-fbdev"
                if [ -x "$fallback" ]; then
                    local fb_missing
                    fb_missing=$(ldd "$fallback" 2>/dev/null | grep "not found" || true)
                    if [ -z "$fb_missing" ]; then
                        log_warn "DRM binary has missing GL libraries -- fbdev fallback will be used"
                        log_warn "Install GPU libraries for hardware acceleration: sudo apt install libgbm1 libegl1 libgles2"
                        return 0
                    fi
                fi
                # Under NoNewPrivileges (self-update), we can't install libs.
                # Warn but don't block — the binary may still start with reduced
                # functionality (e.g. no SIMD camera decode).
                if _has_no_new_privs; then
                    log_warn "Missing libraries (cannot install during self-update):"
                    echo "$missing_libs" | while IFS= read -r line; do
                        log_warn "  $line"
                    done
                    # Extract library basenames (e.g. "libturbojpeg.so.0") for user guidance
                    local lib_names
                    lib_names=$(echo "$missing_libs" | awk '{print $1}' | tr '\n' ' ')
                    log_warn "Install manually: sudo apt-get install packages providing: $lib_names"
                    return 0
                fi
                # No usable fallback — original error behavior
                log_error "Could not resolve all missing libraries:"
                echo "$missing_libs" | while IFS= read -r line; do
                    log_error "  $line"
                done
                log_error "The binary may not start correctly."
                log_error "Please report this issue at https://github.com/prestonbrown/helixscreen/issues"
                exit 1
            fi
            log_success "All shared library dependencies resolved"
            ;;
        *)
            # Non-Pi platforms: just warn, don't block
            log_warn "Some libraries are missing. The binary may not start correctly."
            ;;
    esac
}

# ============================================
# Module: forgex.sh
# ============================================

#
# Configure ForgeX display settings for HelixScreen
# We use GUPPY mode because ForgeX handles backlight properly in this mode.
# STOCK mode expects ffstartup-arm to manage display/backlight which doesn't work for us.
# We disable GuppyScreen's init scripts so HelixScreen takes over the display.
configure_forgex_display() {
    var_file="/opt/config/mod_data/variables.cfg"
    guppy_init="/opt/config/mod/.root/S80guppyscreen"
    tslib_init="/opt/config/mod/.root/S35tslib"
    changed=false

    # Set display mode to GUPPY (required for backlight to work)
    if [ -f "$var_file" ]; then
        if grep -q "display[[:space:]]*=[[:space:]]*'STOCK'" "$var_file"; then
            log_info "Setting ForgeX display mode to GUPPY..."
            $SUDO sed -i "s/display[[:space:]]*=[[:space:]]*'STOCK'/display = 'GUPPY'/" "$var_file"
            changed=true
        elif grep -q "display[[:space:]]*=[[:space:]]*'HEADLESS'" "$var_file"; then
            log_info "Setting ForgeX display mode to GUPPY..."
            $SUDO sed -i "s/display[[:space:]]*=[[:space:]]*'HEADLESS'/display = 'GUPPY'/" "$var_file"
            changed=true
        fi
    fi

    # Disable GuppyScreen init script (remove execute permission)
    if [ -x "$guppy_init" ]; then
        log_info "Disabling GuppyScreen init script..."
        $SUDO chmod a-x "$guppy_init"
        changed=true
    fi

    # Disable tslib init script (GuppyScreen's touch input layer)
    # HelixScreen uses its own input handling
    if [ -x "$tslib_init" ]; then
        log_info "Disabling tslib init script..."
        $SUDO chmod a-x "$tslib_init"
        changed=true
    fi

    if [ "$changed" = true ]; then
        log_success "ForgeX configured for HelixScreen (GUPPY mode, GuppyScreen disabled)"
        return 0
    fi
    return 1
}

# Patch ForgeX screen.sh to skip non-100 backlight control when HelixScreen is active
# ForgeX's headless.cfg runs a delayed_gcode that dims the backlight 3 seconds after
# Klipper starts. This patch blocks dimming calls but allows the S99root 0→100 cycle.
#
# The smart patch:
# - Allows "backlight 100" (needed for S99root initialization cycle)
# - Blocks other values (10, 0, etc.) when helixscreen_active flag exists
patch_forgex_screen_sh() {
    screen_sh="/opt/config/mod/.shell/screen.sh"

    if [ ! -f "$screen_sh" ]; then
        log_info "ForgeX screen.sh not found, skipping patch"
        return 1
    fi

    # Check if already patched (look for the smart patch signature)
    if grep -q 'helixscreen_active.*!=.*100' "$screen_sh" 2>/dev/null; then
        log_info "ForgeX screen.sh already has smart patch"
        return 0
    fi

    # Remove old-style patch if present (blocks ALL backlight when flag exists)
    if grep -q "helixscreen_active" "$screen_sh" 2>/dev/null; then
        log_info "Removing old-style patch from screen.sh..."
        tmp_file="${screen_sh}.tmp"
        grep -v "helixscreen_active\|# Skip if HelixScreen" "$screen_sh" > "$tmp_file"
        $SUDO mv "$tmp_file" "$screen_sh"
        $SUDO chmod +x "$screen_sh"
    fi

    # Find the backlight) case and add our guard
    if ! grep -q "^[[:space:]]*backlight)" "$screen_sh"; then
        log_info "Could not find backlight case in screen.sh"
        return 1
    fi

    log_info "Patching ForgeX screen.sh with smart backlight control..."

    # Use awk to insert our check after "backlight)" line (BusyBox compatible)
    # Smart patch: only block non-100 values, allowing S99root's 0→100 init cycle
    tmp_file="${screen_sh}.tmp"
    awk '
    /^[[:space:]]*backlight\)/ {
        print
        print "        # Skip non-100 backlight changes when HelixScreen is controlling display"
        print "        # Allows S99root 0->100 init cycle but blocks Klipper eco dimming"
        print "        if [ -f /tmp/helixscreen_active ] && [ \"$2\" != \"100\" ]; then"
        print "            exit 0"
        print "        fi"
        next
    }
    { print }
    ' "$screen_sh" > "$tmp_file"

    if [ -s "$tmp_file" ] && grep -q 'helixscreen_active.*!=.*100' "$tmp_file" 2>/dev/null; then
        $SUDO mv "$tmp_file" "$screen_sh"
        $SUDO chmod +x "$screen_sh"
        log_success "ForgeX screen.sh patched with smart backlight control"
        return 0
    else
        rm -f "$tmp_file"
        log_warn "Failed to patch ForgeX screen.sh"
        return 1
    fi
}

# Remove HelixScreen patch from ForgeX screen.sh (for uninstall)
unpatch_forgex_screen_sh() {
    screen_sh="/opt/config/mod/.shell/screen.sh"

    if [ ! -f "$screen_sh" ]; then
        return 1
    fi

    # Check if patched
    if ! grep -q "helixscreen_active" "$screen_sh" 2>/dev/null; then
        log_info "ForgeX screen.sh not patched, nothing to remove"
        return 0
    fi

    log_info "Removing HelixScreen patch from ForgeX screen.sh..."

    # Use awk to remove only our specific block (BusyBox compatible)
    # Match and skip: comment line, if line with helixscreen_active, exit 0, fi
    tmp_file="${screen_sh}.tmp"
    awk '
    /# Skip if HelixScreen is controlling the display/ { skip=1; next }
    /if \[ -f \/tmp\/helixscreen_active \]; then/ { skip=1; next }
    skip && /^[[:space:]]*exit 0[[:space:]]*$/ { next }
    skip && /^[[:space:]]*fi[[:space:]]*$/ { skip=0; next }
    { print }
    ' "$screen_sh" > "$tmp_file"

    if [ -s "$tmp_file" ]; then
        $SUDO mv "$tmp_file" "$screen_sh"
        $SUDO chmod +x "$screen_sh"
    else
        rm -f "$tmp_file"
        log_warn "Failed to unpatch ForgeX screen.sh"
        return 1
    fi

    # Verify removal
    if grep -q "helixscreen_active" "$screen_sh" 2>/dev/null; then
        log_warn "Could not fully remove patch from screen.sh"
        return 1
    fi

    log_success "ForgeX screen.sh patch removed"
    return 0
}

# Disable stock FlashForge UI in auto_run.sh
# The stock firmware UI (ffstartup-arm/firmwareExe) is started by /opt/auto_run.sh
# which runs AFTER init scripts. We comment out the line to prevent it starting.
disable_stock_firmware_ui() {
    auto_run="/opt/auto_run.sh"
    if [ -f "$auto_run" ]; then
        # Check if ffstartup-arm line exists and is not already commented
        if grep -q "^/opt/PROGRAM/ffstartup-arm" "$auto_run"; then
            log_info "Disabling stock FlashForge UI in auto_run.sh..."
            # Comment out the ffstartup-arm line
            $SUDO sed -i 's|^/opt/PROGRAM/ffstartup-arm|# Disabled by HelixScreen: /opt/PROGRAM/ffstartup-arm|' "$auto_run"
            log_success "Stock FlashForge UI disabled"
            return 0
        fi
    fi
    return 1
}

# Re-enable stock FlashForge UI in auto_run.sh (for uninstall)
restore_stock_firmware_ui() {
    auto_run="/opt/auto_run.sh"
    if [ -f "$auto_run" ]; then
        # Check if our disabled line exists
        if grep -q "^# Disabled by HelixScreen: /opt/PROGRAM/ffstartup-arm" "$auto_run"; then
            log_info "Re-enabling stock FlashForge UI in auto_run.sh..."
            # Uncomment the ffstartup-arm line
            $SUDO sed -i 's|^# Disabled by HelixScreen: /opt/PROGRAM/ffstartup-arm|/opt/PROGRAM/ffstartup-arm|' "$auto_run"
            log_success "Stock FlashForge UI re-enabled"
            return 0
        fi
    fi
    return 1
}

# Patch ForgeX screen.sh to skip screen drawing when HelixScreen is active
# ForgeX's S99root calls draw_splash, draw_loading, and boot_message which write
# directly to the framebuffer, overwriting our splash screen during boot.
patch_forgex_screen_drawing() {
    screen_sh="/opt/config/mod/.shell/screen.sh"

    if [ ! -f "$screen_sh" ]; then
        log_info "ForgeX screen.sh not found, skipping screen drawing patch"
        return 1
    fi

    # Check if already patched (look for our signature in draw_splash)
    if grep -q 'draw_splash)' "$screen_sh" && \
       grep -A2 'draw_splash)' "$screen_sh" | grep -q 'helixscreen_active'; then
        log_info "ForgeX screen.sh already has screen drawing patches"
        return 0
    fi

    log_info "Patching ForgeX screen.sh to skip drawing when HelixScreen active..."

    # Patch draw_loading, draw_splash, and boot_message cases
    # Add helixscreen_active check after each case label
    tmp_file="${screen_sh}.tmp"
    awk '
    /^[[:space:]]*(draw_loading|draw_splash|boot_message)\)/ {
        print
        print "        # Skip when HelixScreen is controlling display"
        print "        if [ -f /tmp/helixscreen_active ]; then"
        print "            exit 0"
        print "        fi"
        next
    }
    { print }
    ' "$screen_sh" > "$tmp_file"

    if [ -s "$tmp_file" ] && grep -q 'helixscreen_active' "$tmp_file" 2>/dev/null; then
        $SUDO mv "$tmp_file" "$screen_sh"
        $SUDO chmod +x "$screen_sh"
        log_success "ForgeX screen.sh patched for screen drawing"
        return 0
    else
        rm -f "$tmp_file"
        log_warn "Failed to patch ForgeX screen.sh for screen drawing"
        return 1
    fi
}

# Remove screen drawing patches from ForgeX screen.sh (for uninstall)
unpatch_forgex_screen_drawing() {
    screen_sh="/opt/config/mod/.shell/screen.sh"

    if [ ! -f "$screen_sh" ]; then
        return 1
    fi

    # Check if our drawing patches are present
    if ! grep -q '# Skip when HelixScreen is controlling display' "$screen_sh" 2>/dev/null; then
        log_info "ForgeX screen.sh has no drawing patches, nothing to remove"
        return 0
    fi

    log_info "Removing HelixScreen drawing patches from ForgeX screen.sh..."

    # Remove our 4-line block: comment + if + exit 0 + fi
    tmp_file="${screen_sh}.tmp"
    awk '
    /# Skip when HelixScreen is controlling display/ { skip=1; next }
    skip && /if \[ -f \/tmp\/helixscreen_active \]; then/ { next }
    skip && /^[[:space:]]*exit 0[[:space:]]*$/ { next }
    skip && /^[[:space:]]*fi[[:space:]]*$/ { skip=0; next }
    { print }
    ' "$screen_sh" > "$tmp_file"

    if [ -s "$tmp_file" ]; then
        $SUDO mv "$tmp_file" "$screen_sh"
        $SUDO chmod +x "$screen_sh"
    else
        rm -f "$tmp_file"
        log_warn "Failed to unpatch ForgeX screen.sh drawing patches"
        return 1
    fi

    # Verify removal
    if grep -q '# Skip when HelixScreen is controlling display' "$screen_sh" 2>/dev/null; then
        log_warn "Could not fully remove drawing patches from screen.sh"
        return 1
    fi

    log_success "ForgeX screen.sh drawing patches removed"
    return 0
}

# Install logged wrapper to prevent direct framebuffer writes during boot
# ForgeX's 'logged' binary writes directly to /dev/fb0 when --send-to-screen is used,
# bypassing our screen.sh patches. This wrapper strips that flag when HelixScreen is active.
install_forgex_logged_wrapper() {
    logged_bin="/opt/config/mod/.bin/exec/logged"
    logged_real="/opt/config/mod/.bin/exec/logged-real"
    logged_wrapper="/opt/config/mod/.bin/exec/logged-wrapper"

    if [ ! -f "$logged_bin" ]; then
        log_info "ForgeX logged binary not found, skipping wrapper"
        return 1
    fi

    # Always re-write the wrapper to pick up fixes on upgrade
    if [ -L "$logged_bin" ] && [ -f "$logged_real" ]; then
        log_info "Updating ForgeX logged wrapper..."
    elif [ -L "$logged_bin" ]; then
        # Don't wrap if it's already a symlink to something else
        log_warn "ForgeX logged is already a symlink, skipping wrapper"
        return 1
    else
        log_info "Installing ForgeX logged wrapper..."
    fi

    # Create the wrapper script
    cat > "$logged_wrapper" << 'WRAPPER_EOF'
# Wrapper for logged that strips --send-to-screen when HelixScreen is active
# The logged binary writes directly to /dev/fb0, bypassing screen.sh patches

if [ -f /tmp/helixscreen_active ]; then
    # Remove --send-to-screen and related args, keep everything else
    args=""
    skip_next=0
    for arg in "$@"; do
        if [ $skip_next -eq 1 ]; then
            skip_next=0
            continue
        fi
        case "$arg" in
            --send-to-screen) continue ;;
            --screen-no-followup) continue ;;
            --screen-level) skip_next=1; continue ;;
            --screen-queue) skip_next=1; continue ;;
            *) args="$args $arg" ;;
        esac
    done
    exec /opt/config/mod/.bin/exec/logged-real $args
else
    exec /opt/config/mod/.bin/exec/logged-real "$@"
fi
WRAPPER_EOF

    $SUDO chmod +x "$logged_wrapper"

    # Move original to logged-real and symlink logged to wrapper (skip if already done)
    if [ ! -L "$logged_bin" ]; then
        $SUDO mv "$logged_bin" "$logged_real"
        $SUDO ln -s "$logged_wrapper" "$logged_bin"
    fi

    if [ -L "$logged_bin" ] && [ -f "$logged_real" ]; then
        log_success "ForgeX logged wrapper installed"
        return 0
    else
        # Rollback on failure
        [ -f "$logged_real" ] && $SUDO mv "$logged_real" "$logged_bin"
        rm -f "$logged_wrapper"
        log_warn "Failed to install ForgeX logged wrapper"
        return 1
    fi
}

# Remove logged wrapper (for uninstall)
uninstall_forgex_logged_wrapper() {
    logged_bin="/opt/config/mod/.bin/exec/logged"
    logged_real="/opt/config/mod/.bin/exec/logged-real"
    logged_wrapper="/opt/config/mod/.bin/exec/logged-wrapper"

    if [ ! -f "$logged_real" ]; then
        return 0  # Not installed
    fi

    log_info "Removing ForgeX logged wrapper..."

    $SUDO rm -f "$logged_bin"
    $SUDO mv "$logged_real" "$logged_bin"
    $SUDO rm -f "$logged_wrapper"

    log_success "ForgeX logged wrapper removed"
    return 0
}

# Uninstall ForgeX-specific configuration (for uninstall)
# Restores display mode, stock UI, screen.sh, GuppyScreen/tslib init scripts,
# and cleans up backup files from manual patches.
# Note: Sets caller's `restored_ui` variable via dynamic scoping.
uninstall_forgex() {
    # Restore ForgeX display mode to GUPPY (from HEADLESS or STOCK)
    if [ -f "/opt/config/mod_data/variables.cfg" ]; then
        if grep -q "display[[:space:]]*=[[:space:]]*'HEADLESS'" "/opt/config/mod_data/variables.cfg"; then
            log_info "Restoring ForgeX display mode to GUPPY..."
            $SUDO sed -i "s/display[[:space:]]*=[[:space:]]*'HEADLESS'/display = 'GUPPY'/" "/opt/config/mod_data/variables.cfg"
        elif grep -q "display[[:space:]]*=[[:space:]]*'STOCK'" "/opt/config/mod_data/variables.cfg"; then
            log_info "Restoring ForgeX display mode to GUPPY..."
            $SUDO sed -i "s/display[[:space:]]*=[[:space:]]*'STOCK'/display = 'GUPPY'/" "/opt/config/mod_data/variables.cfg"
        fi
    fi

    # Restore stock FlashForge UI in auto_run.sh
    restore_stock_firmware_ui || true

    # Remove HelixScreen patches from screen.sh
    unpatch_forgex_screen_sh || true
    unpatch_forgex_screen_drawing || true

    # Remove logged wrapper
    uninstall_forgex_logged_wrapper || true

    # Re-enable GuppyScreen and tslib init scripts
    if [ -f "/opt/config/mod/.root/S80guppyscreen" ]; then
        $SUDO chmod +x "/opt/config/mod/.root/S80guppyscreen" 2>/dev/null || true
        restored_ui="GuppyScreen (/opt/config/mod/.root/S80guppyscreen)"
    fi
    if [ -f "/opt/config/mod/.root/S35tslib" ]; then
        $SUDO chmod +x "/opt/config/mod/.root/S35tslib" 2>/dev/null || true
    fi

    # Clean up any leftover backup files from manual patches
    for backup_file in /opt/config/mod/.shell/*.helix-backup /opt/config/mod/.shell/*.bak; do
        if [ -f "$backup_file" ] 2>/dev/null; then
            log_info "Removing leftover backup: $backup_file"
            $SUDO rm -f "$backup_file"
        fi
    done
}

# ============================================
# Module: service.sh
# ============================================

#
# SERVICE_NAME is defined in common.sh
# Portable in-place sed: GNU sed uses -i, BSD/macOS sed requires -i ''
_sed_inplace() {
    local pattern=$1 file=$2
    $SUDO sed -i "$pattern" "$file" 2>/dev/null || \
    $SUDO sed -i '' "$pattern" "$file" 2>/dev/null || true
}

# Returns true if this process is running under the NoNewPrivileges systemd constraint.
# When helix-screen self-updates, it spawns install.sh as a child process.  The
# helixscreen.service unit has NoNewPrivileges=true, so ALL sudo calls in install.sh
# will fail.  Callers use this to skip operations that require root (service file
# copy, daemon-reload, systemctl start) and instead let update_checker.cpp restart
# the process via exit(0), which the watchdog treats as "restart silently".
_has_no_new_privs() {
    # Primary: check /proc/self/status (kernel 4.10+)
    if [ -r /proc/self/status ] && grep -q '^NoNewPrivs:[[:space:]]*1' /proc/self/status 2>/dev/null; then
        return 0
    fi
    # Fallback for older kernels (e.g. SonicPad 4.9): if we know this is a
    # self-update spawned from the running app, the service unit's
    # NoNewPrivileges=true is inherited — sudo will fail.
    _is_self_update
}

# _is_self_update() is defined in common.sh (sourced before this module)

# Fix a known-broken PLATFORM_HOOKS path in an already-deployed init script.
#
# Init scripts shipped before 2026-04-20 sourced platform hooks from
# ${DAEMON_DIR}/assets/config/platform/hooks.sh, but the installer (and the
# deploy makefile) write hooks to ${DAEMON_DIR}/platform/hooks.sh.  Result:
# the file was never found, platform_stop_competing_uis() stayed a no-op,
# and stock UIs (Creality K2 /etc/init.d/app, etc.) ran alongside HelixScreen.
#
# Self-update deliberately skips copying the init script to preserve
# platform customizations (#314), so a pure source-tree fix can't reach
# already-installed users.  This surgical sed rewrites only that one
# known-broken substring; anything else the platform may have customized
# is left alone.
_migrate_init_script_hooks_path() {
    local init_script="${INIT_SCRIPT_DEST:-}"
    [ -n "$init_script" ] && [ -f "$init_script" ] || return 0
    if grep -q 'assets/config/platform/hooks\.sh' "$init_script" 2>/dev/null; then
        log_info "Migrating stale PLATFORM_HOOKS path in $init_script"
        _sed_inplace 's|assets/config/platform/hooks\.sh|platform/hooks.sh|' "$init_script"
    fi
}

# Install service (dispatcher)
# Calls install_service_systemd or install_service_sysv based on INIT_SYSTEM
install_service() {
    local platform=$1

    if [ "$platform" = "snapmaker-u1" ]; then
        install_service_snapmaker_u1
        return
    fi

    if [ "$INIT_SYSTEM" = "systemd" ]; then
        install_service_systemd
    else
        install_service_sysv
        # K2 (procd) needs an extra shim — see install_procd_shim_k2
        if [ "$platform" = "k2" ]; then
            install_procd_shim_k2
        fi
    fi
}

# K2 (Tina Linux / procd) requires init scripts to use the rc.common
# shebang AND declare a DEPEND directive — without both, procd's boot
# iterator silently skips them. Our shared SysV-style S99helixscreen has
# neither, so on K2 it's never auto-started at boot, leaving the device
# stuck on the Creality boot logo with no UI.
#
# Fix: install a tiny procd-compatible /etc/init.d/helixscreen shim that
# delegates every action to the real SysV script. Replace any existing
# rc.d symlink (older installs pointed it at the SysV script directly,
# which procd silently skips).
install_procd_shim_k2() {
    local shim_dest="/etc/init.d/helixscreen"

    if [ ! -x /etc/rc.common ]; then
        log_warn "K2 procd shim: /etc/rc.common not found — skipping (boot autostart will not work)"
        return 0
    fi

    log_info "Installing K2 procd boot shim..."
    $SUDO tee "$shim_dest" >/dev/null <<'SHIM_EOF'
# K2 procd shim — delegates to the SysV-style /etc/init.d/S99helixscreen.
# Required because K2's procd boot iterator only invokes scripts with the
# rc.common shebang AND a DEPEND directive; plain SysV scripts are silently
# skipped at boot.
START=99
STOP=01
DEPEND=done

boot()    { /etc/init.d/S99helixscreen start; }
start()   { /etc/init.d/S99helixscreen start; }
stop()    { /etc/init.d/S99helixscreen stop; }
restart() { /etc/init.d/S99helixscreen restart; }
status()  { /etc/init.d/S99helixscreen status; }
SHIM_EOF
    $SUDO chmod +x "$shim_dest"

    # Older installs symlinked /etc/rc.d/S99helixscreen directly to the SysV
    # script, which procd skips. Drop those, then let rc.common's enable
    # create fresh S99/K01 symlinks pointing at the shim.
    $SUDO rm -f /etc/rc.d/S99helixscreen /etc/rc.d/K01helixscreen
    if ! $SUDO "$shim_dest" enable; then
        log_warn "K2 procd shim: enable failed — UI will not autostart at boot"
        log_warn "Manual fix: $SUDO $shim_dest enable"
        return 1
    fi

    log_success "Installed K2 procd shim at $shim_dest"
}

install_service_snapmaker_u1() {
    log_info "Configuring Snapmaker U1 autostart..."

    # --- Fix DAEMON_DIR in the init script (U1 keeps it in-place, not /etc/init.d/) ---
    local init_script="${INSTALL_DIR}/config/helixscreen.init"
    if [ ! -f "$init_script" ]; then
        log_error "Init script not found: $init_script"
        exit 1
    fi
    chmod +x "$init_script"
    _sed_inplace "s|DAEMON_DIR=.*|DAEMON_DIR=\"${INSTALL_DIR}\"|" "$init_script"

    # --- Patch S99screen to delegate to helixscreen.init on boot ---
    if [ -f "${INSTALL_DIR}/scripts/snapmaker-u1-setup-autostart.sh" ]; then
        if ! bash "${INSTALL_DIR}/scripts/snapmaker-u1-setup-autostart.sh" "${INSTALL_DIR}"; then
            log_error "Snapmaker U1 autostart configuration failed."
            log_error "Ensure /oem and /etc/init.d are writable."
            exit 1
        fi
    else
        log_error "Snapmaker U1 autostart script not found at ${INSTALL_DIR}/scripts/snapmaker-u1-setup-autostart.sh"
        log_error "The release package may be incomplete."
        log_error "Recovery: re-run the installer to download a fresh copy:"
        log_error "  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
        exit 1
    fi
}

# Install systemd service
install_service_systemd() {
    # During self-update, the main service file is already installed and may
    # contain platform customizations (#314) — don't overwrite it.
    # BUT: always update the update-watcher units (path + oneshot service).
    # They have no platform customizations and older versions had a PathExists
    # bug that causes an infinite restart loop after any update.
    if _is_self_update; then
        log_info "Skipping main service file install (self-update; preserving customizations)"
        update_watcher_if_stale
        CLEANUP_SERVICE=true
        return 0
    fi

    log_info "Installing systemd service..."

    local service_src="${INSTALL_DIR}/config/helixscreen.service"
    local service_dest="/etc/systemd/system/${SERVICE_NAME}.service"

    if [ ! -f "$service_src" ]; then
        log_error "Service file not found: $service_src"
        log_error "The release package may be incomplete."
        log_error "Recovery: re-run the installer to download a fresh copy:"
        log_error "  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
        exit 1
    fi

    # Under NoNewPrivileges (self-update spawned by helix-screen), sudo is blocked and
    # /etc/systemd/system/ is read-only in the service's mount namespace.  The service
    # is already installed and correct — skip reinstall.  The process restart is handled
    # by update_checker.cpp calling exit(0) after install.sh succeeds.
    if _has_no_new_privs; then
        if [ -f "$service_dest" ]; then
            log_info "Skipping service reinstall (NoNewPrivileges; already installed)"
            CLEANUP_SERVICE=true
            return 0
        fi
        log_error "Service not installed and NoNewPrivileges prevents installation"
        exit 1
    fi

    $SUDO cp "$service_src" "$service_dest"

    # Template placeholders (match SysV pattern in install_service_sysv).
    # KLIPPER_GROUP is the user's actual primary group (resolved via id -gn);
    # falling back to KLIPPER_USER would re-introduce the QIDI Q2 bug where
    # `mks` user has no `mks` group and systemd refuses to spawn the unit.
    local helix_user="${KLIPPER_USER:-root}"
    local helix_group="${KLIPPER_GROUP:-${KLIPPER_USER:-root}}"
    local install_dir="${INSTALL_DIR:-/opt/helixscreen}"

    local install_parent
    install_parent="$(dirname "${install_dir}")"

    _sed_inplace "s|@@HELIX_USER@@|${helix_user}|g" "$service_dest"
    _sed_inplace "s|@@HELIX_GROUP@@|${helix_group}|g" "$service_dest"
    _sed_inplace "s|@@INSTALL_DIR@@|${install_dir}|g" "$service_dest"
    _sed_inplace "s|@@INSTALL_PARENT@@|${install_parent}|g" "$service_dest"

    if ! $SUDO systemctl daemon-reload; then
        log_error "Failed to reload systemd daemon."
        exit 1
    fi

    # Install update watcher (restarts helixscreen after Moonraker web-type update)
    # Workaround for mainsail-crew/mainsail#2444: type: web lacks managed_services
    install_update_watcher_systemd

    CLEANUP_SERVICE=true
    log_success "Installed systemd service"
}

# During self-update, check if the deployed update-watcher path unit has the
# old PathExists directive (which causes infinite restart loops) and fix it.
# The watcher units have no platform customizations — only @@INSTALL_DIR@@.
# Under NoNewPrivileges we can't write to /etc/systemd/system/ or run
# systemctl daemon-reload, so we rely on helixscreen-update.service's
# ExecStartPre to refresh the main service file on next Moonraker update.
# However, the PATH unit itself won't get refreshed that way, so we attempt
# a direct fix here and fall back to a warning if permissions block it.
update_watcher_if_stale() {
    local path_dest="/etc/systemd/system/helixscreen-update.path"
    local svc_dest="/etc/systemd/system/helixscreen-update.service"

    # Only relevant on systemd with the watcher installed
    [ "$INIT_SYSTEM" = "systemd" ] || return 0
    [ -f "$path_dest" ] || return 0

    # Detect staleness: PathExists bug (restart loop), missing sentinel check
    # (self-update double-trigger #536), or missing refresh-service-units.sh.
    local stale=false reason=""
    if grep -q '^PathExists=' "$path_dest" 2>/dev/null; then
        stale=true reason="PathExists bug (restart loop)"
    elif [ -f "$svc_dest" ] && ! grep -q 'self_restart_sentinel' "$svc_dest" 2>/dev/null; then
        stale=true reason="missing self-update sentinel check (#536)"
    elif [ -f "$svc_dest" ] && ! grep -q 'refresh-service-units' "$svc_dest" 2>/dev/null; then
        stale=true reason="missing service file refresh"
    fi

    if ! $stale; then
        log_info "Update watcher units are current"
        return 0
    fi

    log_warn "Stale update watcher units: $reason"

    local path_src="${INSTALL_DIR}/config/helixscreen-update.path"
    local svc_src="${INSTALL_DIR}/config/helixscreen-update.service"
    local install_dir="${INSTALL_DIR:-/opt/helixscreen}"
    local install_parent
    install_parent="$(dirname "$install_dir")"

    if _has_no_new_privs; then
        # Can't write to /etc/systemd/system/ under NoNewPrivileges.
        # Attempt in-place fixes — may fail under ProtectSystem=strict.
        local fixed=false
        if grep -q '^PathExists=' "$path_dest" 2>/dev/null; then
            sed -i 's/^PathExists=/PathChanged=/' "$path_dest" 2>/dev/null && fixed=true
        fi
        if [ -f "$svc_src" ] && [ -f "$svc_dest" ]; then
            if cp "$svc_src" "$svc_dest" 2>/dev/null; then
                sed -i -e "s|@@INSTALL_DIR@@|${install_dir}|g" \
                       -e "s|@@INSTALL_PARENT@@|${install_parent}|g" \
                    "$svc_dest" 2>/dev/null
                fixed=true
            fi
        fi
        if $fixed; then
            log_success "Updated watcher units (best-effort under NoNewPrivileges)"
        else
            log_warn "Cannot update watcher units under NoNewPrivileges."
            log_warn "Fix: sudo ${install_dir}/config/refresh-service-units.sh"
        fi
        return 0
    fi

    # Have sudo access — do a full replacement
    if [ -f "$path_src" ] && [ -f "$svc_src" ]; then
        $SUDO cp "$path_src" "$path_dest"
        $SUDO cp "$svc_src" "$svc_dest"
        _sed_inplace "s|@@INSTALL_DIR@@|${install_dir}|g" "$path_dest"
        _sed_inplace "s|@@INSTALL_DIR@@|${install_dir}|g" "$svc_dest"
        _sed_inplace "s|@@INSTALL_PARENT@@|${install_parent}|g" "$path_dest"
        _sed_inplace "s|@@INSTALL_PARENT@@|${install_parent}|g" "$svc_dest"
        $SUDO systemctl daemon-reload 2>/dev/null || true
        $SUDO systemctl restart helixscreen-update.path 2>/dev/null || true
        log_success "Updated watcher units ($reason)"
    fi
}

# Install systemd path unit that restarts helixscreen after Moonraker extracts an update
install_update_watcher_systemd() {
    local path_src="${INSTALL_DIR}/config/helixscreen-update.path"
    local svc_src="${INSTALL_DIR}/config/helixscreen-update.service"
    local path_dest="/etc/systemd/system/helixscreen-update.path"
    local svc_dest="/etc/systemd/system/helixscreen-update.service"

    if [ ! -f "$path_src" ] || [ ! -f "$svc_src" ]; then
        log_info "Update watcher units not found, skipping"
        return 0
    fi

    local install_dir="${INSTALL_DIR:-/opt/helixscreen}"

    $SUDO cp "$path_src" "$path_dest"
    $SUDO cp "$svc_src" "$svc_dest"

    # Template the install directory path in both units
    _sed_inplace "s|@@INSTALL_DIR@@|${install_dir}|g" "$path_dest"
    _sed_inplace "s|@@INSTALL_DIR@@|${install_dir}|g" "$svc_dest"

    $SUDO systemctl daemon-reload
    $SUDO systemctl enable helixscreen-update.path 2>/dev/null || true
    $SUDO systemctl start helixscreen-update.path 2>/dev/null || true

    log_info "Installed update watcher (helixscreen-update.path)"
}

# Install SysV init script
install_service_sysv() {
    # During self-update, the init script is already installed and correct.
    # Overwriting it destroys platform customizations (ZMOD, Klipper Mod) (#314).
    if _is_self_update; then
        log_info "Skipping init script install (self-update; already installed)"
        _migrate_init_script_hooks_path
        CLEANUP_SERVICE=true
        return 0
    fi

    log_info "Installing SysV init script..."

    local init_src="${INSTALL_DIR}/config/helixscreen.init"

    if [ ! -f "$init_src" ]; then
        log_error "Init script not found: $init_src"
        log_error "The release package may be incomplete."
        log_error "Recovery: re-run the installer to download a fresh copy:"
        log_error "  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
        exit 1
    fi

    # Use the dynamically set INIT_SCRIPT_DEST (varies by firmware)
    $SUDO cp "$init_src" "$INIT_SCRIPT_DEST"
    $SUDO chmod +x "$INIT_SCRIPT_DEST"

    # Update the DAEMON_DIR in the init script to match the install location
    # This is important for Klipper Mod which uses a different path
    _sed_inplace "s|DAEMON_DIR=.*|DAEMON_DIR=\"${INSTALL_DIR}\"|" "$INIT_SCRIPT_DEST"

    CLEANUP_SERVICE=true
    log_success "Installed SysV init script at $INIT_SCRIPT_DEST"
}

# Start service (dispatcher)
# Calls start_service_systemd or start_service_sysv based on INIT_SYSTEM.
# Snapmaker U1 uses its own init script path (patched S99screen, not S99helixscreen).
start_service() {
    local platform=${1:-}

    if [ "$platform" = "snapmaker-u1" ]; then
        start_service_snapmaker_u1
        return
    fi

    if [ "$INIT_SYSTEM" = "systemd" ]; then
        start_service_systemd
    else
        start_service_sysv
    fi
}

# Start service (Snapmaker U1)
# The U1 patches /etc/init.d/S99screen to delegate to helixscreen.init;
# there is no standalone S99helixscreen init script.
start_service_snapmaker_u1() {
    if _is_self_update; then
        log_info "Skipping service start (self-update; restart via watchdog)"
        return 0
    fi

    log_info "Starting HelixScreen (Snapmaker U1)..."

    local init_src="${INSTALL_DIR}/config/helixscreen.init"
    if [ ! -x "$init_src" ]; then
        chmod +x "$init_src" 2>/dev/null || true
    fi

    if [ ! -x "$init_src" ]; then
        log_error "Init script not found or not executable: $init_src"
        log_error "The release package may be incomplete."
        log_error "Recovery: re-run the installer to download a fresh copy:"
        log_error "  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
        exit 1
    fi

    if ! $SUDO "$init_src" start; then
        log_error "Failed to start HelixScreen."
        log_error "Check logs: /var/log/helixscreen/launcher.log or ${INSTALL_DIR}/logs/launcher.log"
        exit 1
    fi

    # Wait for service to start (may be slow on embedded hardware)
    local i
    for i in 1 2 3 4 5; do
        sleep 1
        if pidof helix-screen >/dev/null 2>&1; then
            log_success "HelixScreen is running!"
            return
        fi
    done
    log_warn "Service may still be starting..."
    log_warn "Check logs: /var/log/helixscreen/launcher.log or ${INSTALL_DIR}/logs/launcher.log"
}

# Start service (systemd)
start_service_systemd() {
    log_info "Enabling and starting HelixScreen (systemd)..."

    # Under NoNewPrivileges, systemctl is blocked.  The restart is handled by
    # update_checker.cpp: it calls exit(0) after we return, which the watchdog
    # treats as "normal exit — restart silently".
    if _has_no_new_privs; then
        log_info "Skipping service start (NoNewPrivileges; restart via watchdog)"
        return 0
    fi

    if ! $SUDO systemctl enable "$SERVICE_NAME"; then
        log_error "Failed to enable ${SERVICE_NAME} service."
        exit 1
    fi

    if ! $SUDO systemctl start "$SERVICE_NAME"; then
        log_error "Failed to start ${SERVICE_NAME} service."
        log_error "Check logs with: journalctl -u ${SERVICE_NAME} -n 50"
        exit 1
    fi

    # Wait for service to start (may be slow on embedded hardware)
    local i
    for i in 1 2 3 4 5; do
        sleep 1
        if systemctl is-active --quiet "$SERVICE_NAME"; then
            log_success "HelixScreen is running!"
            return
        fi
    done
    log_warn "Service may still be starting..."
    log_warn "Check status with: systemctl status $SERVICE_NAME"
}

# Start service (SysV init)
start_service_sysv() {
    # During in-app self-update, the watchdog handles the restart via _exit(0).
    # Starting a second instance here would race with the still-running process.
    if _is_self_update; then
        log_info "Skipping service start (self-update; restart via watchdog)"
        return 0
    fi

    log_info "Starting HelixScreen (SysV init)..."

    if [ ! -x "$INIT_SCRIPT_DEST" ]; then
        log_error "Init script not executable: $INIT_SCRIPT_DEST"
        exit 1
    fi

    if ! $SUDO "$INIT_SCRIPT_DEST" start; then
        log_error "Failed to start HelixScreen."
        log_error "Check logs: /var/log/helixscreen/launcher.log or ${INSTALL_DIR}/logs/launcher.log"
        exit 1
    fi

    # Wait for service to start (may be slow on embedded hardware)
    local i
    for i in 1 2 3 4 5; do
        sleep 1
        if $SUDO "$INIT_SCRIPT_DEST" status >/dev/null 2>&1; then
            log_success "HelixScreen is running!"
            return
        fi
    done
    log_warn "Service may still be starting..."
    log_warn "Check: $INIT_SCRIPT_DEST status"
}

# Deploy platform-specific hook file
# Copies the correct hook file to $INSTALL_DIR/platform/hooks.sh so the
# init script can source it at runtime.
deploy_platform_hooks() {
    local install_dir="$1"
    local platform="$2"  # "ad5m-forgex", "ad5m-kmod", "pi", "k1"
    # Tarball ships platform hooks under assets/config/ as part of the
    # read-only seed bundle (see scripts/package.sh). Older installers looked
    # in config/platform/ — that path moved in the config/→assets/config/
    # refactor and the deploy_platform_hooks lookup got left behind,
    # silently dropping the hooks file for every sysv platform (#k2-no-hooks).
    local hooks_src="${install_dir}/assets/config/platform/hooks-${platform}.sh"

    if [ ! -f "$hooks_src" ]; then
        log_warn "No platform hooks for: $platform"
        return 0
    fi

    # Try without sudo first: during self-update INSTALL_DIR is pi-owned so no root
    # is needed.  Fall back to sudo for fresh installs where the directory may be
    # root-owned or not yet created.  Under NoNewPrivileges sudo is blocked, so
    # the sudo fallbacks must be silent and non-fatal.
    mkdir -p "${install_dir}/platform" 2>/dev/null || $SUDO mkdir -p "${install_dir}/platform" 2>/dev/null || true
    cp "$hooks_src" "${install_dir}/platform/hooks.sh" 2>/dev/null || $SUDO cp "$hooks_src" "${install_dir}/platform/hooks.sh" 2>/dev/null || true
    chmod +x "${install_dir}/platform/hooks.sh" 2>/dev/null || $SUDO chmod +x "${install_dir}/platform/hooks.sh" 2>/dev/null || true
    log_info "Deployed platform hooks: $platform"
}

# Fix ownership of install directory for non-root service users.
# The entire INSTALL_DIR must be user-owned so that in-app self-updates
# (which run under NoNewPrivileges=true, blocking sudo) can replace
# files without root access.  ProtectSystem=strict in the service file
# limits filesystem writes to ReadWritePaths regardless of ownership.
# Uses -h to avoid following symlinks outside INSTALL_DIR.
fix_install_ownership() {
    local user="${KLIPPER_USER:-}"
    local group="${KLIPPER_GROUP:-$user}"
    if [ -n "$user" ] && [ "$user" != "root" ] && [ -d "$INSTALL_DIR" ]; then
        log_info "Setting ownership to ${user}:${group}..."
        # Try without sudo first: during self-update under NoNewPrivileges,
        # sudo is blocked but files are already user-owned so chown succeeds
        # without it (or is a no-op).  Fall back to sudo for fresh installs
        # where root may own the directory.
        chown -Rh "${user}:${group}" "${INSTALL_DIR}" 2>/dev/null || \
            $SUDO chown -Rh "${user}:${group}" "${INSTALL_DIR}" 2>/dev/null || true
    fi
}

# Stop service for update
stop_service() {
    local platform=${1:-}

    if [ "$platform" = "snapmaker-u1" ]; then
        stop_service_snapmaker_u1
        return
    fi

    if [ "$INIT_SYSTEM" = "systemd" ]; then
        # Under NoNewPrivileges (self-update), sudo is blocked.  The service will be
        # restarted by the watchdog after exit(0) — stopping it here isn't needed.
        if _has_no_new_privs; then
            log_info "Skipping service stop (NoNewPrivileges; restart via watchdog)"
        elif systemctl is-active --quiet "$SERVICE_NAME" 2>/dev/null; then
            log_info "Stopping existing HelixScreen service (systemd)..."
            $SUDO systemctl stop "$SERVICE_NAME" || true
        fi
    else
        # During in-app self-update, the app must stay running so the user sees
        # the update progress screen.  The watchdog restarts via _exit(0) after
        # install.sh exits — killing the process here would black-screen the display.
        if _is_self_update; then
            log_info "Skipping service stop (self-update; restart via watchdog)"
        else
            # Try the configured init script location first
            if [ -n "$INIT_SCRIPT_DEST" ] && [ -x "$INIT_SCRIPT_DEST" ]; then
                log_info "Stopping existing HelixScreen service (SysV)..."
                $SUDO "$INIT_SCRIPT_DEST" stop 2>/dev/null || true
            fi
            # Also check all possible locations (for updates/uninstalls)
            for init_script in $HELIX_INIT_SCRIPTS; do
                if [ -x "$init_script" ]; then
                    log_info "Stopping HelixScreen at $init_script..."
                    $SUDO "$init_script" stop 2>/dev/null || true
                fi
            done
            # Also try to kill by name (watchdog first to prevent crash dialog flash)
            # shellcheck disable=SC2086
            kill_process_by_name $HELIX_PROCESSES || true
        fi
    fi
}

# Stop service (Snapmaker U1)
stop_service_snapmaker_u1() {
    if _is_self_update; then
        log_info "Skipping service stop (self-update; restart via watchdog)"
        return
    fi

    local init_src="${INSTALL_DIR}/config/helixscreen.init"
    if [ -x "$init_src" ]; then
        log_info "Stopping existing HelixScreen service (Snapmaker U1)..."
        $SUDO "$init_src" stop 2>/dev/null || true
    fi
    # Also kill by name in case init script stop didn't clean up
    # shellcheck disable=SC2086
    kill_process_by_name $HELIX_PROCESSES || true
}

# ============================================
# Module: moonraker.sh
# ============================================

#
# Common moonraker.conf locations
# ZMOD-on-AD5X notes:
#   /opt/config is a symlink to /usr/data/config; printer_data lives under both.
#   We list both forms so symlink-aware and -unaware path resolutions both hit.
MOONRAKER_CONF_PATHS="
/home/pi/printer_data/config/moonraker.conf
/home/biqu/printer_data/config/moonraker.conf
/home/mks/printer_data/config/moonraker.conf
/root/printer_data/config/moonraker.conf
/opt/config/printer_data/config/moonraker.conf
/opt/config/moonraker.conf
/usr/data/config/printer_data/config/moonraker.conf
/usr/data/printer_data/config/moonraker.conf
"

# Find moonraker.conf
# Returns: path to moonraker.conf or empty string
find_moonraker_conf() {
    # Dynamic: check detected user's home first
    if [ -n "${KLIPPER_HOME:-}" ]; then
        local user_conf="${KLIPPER_HOME}/printer_data/config/moonraker.conf"
        if [ -f "$user_conf" ]; then
            echo "$user_conf"
            return 0
        fi
    fi

    # Static fallback
    for conf in $MOONRAKER_CONF_PATHS; do
        if [ -f "$conf" ]; then
            echo "$conf"
            return 0
        fi
    done
    echo ""
}

# Check if update_manager section for helixscreen already exists
# Args: $1 = moonraker.conf path
# Returns: 0 if exists, 1 if not
has_update_manager_section() {
    local conf="$1"
    grep -q '^\[update_manager helixscreen\]' "$conf" 2>/dev/null
}

# Generate update_manager configuration block
generate_update_manager_config() {
    cat << EOF

# HelixScreen Update Manager
# Added by HelixScreen installer - enables one-click updates from Mainsail/Fluidd
# NOTE: type: web is used instead of type: zip as a workaround for
# mainsail-crew/mainsail#2444 (zip type always shows UP-TO-DATE).
# A systemd path unit handles service restart after Moonraker extracts the update.
[update_manager helixscreen]
type: web
channel: stable
repo: prestonbrown/helixscreen
path: ${INSTALL_DIR}
EOF
}

# Add update_manager section to moonraker.conf
# Args: $1 = moonraker.conf path
add_update_manager_section() {
    local conf="$1"
    local fs
    fs=$(file_sudo "$conf")

    # Create backup
    $fs cp "$conf" "${conf}.bak.helixscreen" 2>/dev/null || true

    # Append configuration
    generate_update_manager_config | $fs tee -a "$conf" >/dev/null

    log_success "Added update_manager section to $conf"
    log_info "You can now update HelixScreen from the Mainsail/Fluidd web interface!"
}

# Check if moonraker.conf has old git_repo-style helixscreen section
# Args: $1 = moonraker.conf path
# Returns: 0 if old git_repo section found, 1 if not
has_old_git_repo_section() {
    local conf="$1"
    # Look for helixscreen section with type: git_repo
    if grep -q '^\[update_manager helixscreen\]' "$conf" 2>/dev/null; then
        # Extract the section and check for git_repo type
        awk '/^\[update_manager helixscreen\]/{found=1; next} found && /^\[/{exit} found && /^type:/{print; exit}' "$conf" | grep -q 'git_repo'
        return $?
    fi
    return 1
}

# Check if moonraker.conf has old zip-style helixscreen section
# Args: $1 = moonraker.conf path
# Returns: 0 if old zip section found, 1 if not
has_old_zip_section() {
    local conf="$1"
    if grep -q '^\[update_manager helixscreen\]' "$conf" 2>/dev/null; then
        awk '/^\[update_manager helixscreen\]/{found=1; next} found && /^\[/{exit} found && /^type:/{print; exit}' "$conf" | grep -q 'zip'
        return $?
    fi
    return 1
}

# Migrate old section (git_repo or zip) to type: web
# Args: $1 = moonraker.conf path
migrate_to_web_type() {
    local conf="$1"

    log_info "Migrating update_manager to type: web..."

    # Remove old section
    remove_update_manager_section "$conf" 2>/dev/null || true

    # Add new web section
    add_update_manager_section "$conf"

    # Clean up old sparse clone directory if it exists (from git_repo era)
    local old_repo_dir="${INSTALL_DIR}-repo"
    if [ -d "$old_repo_dir" ]; then
        log_info "Removing old updater repo at $old_repo_dir..."
        $SUDO rm -rf "$old_repo_dir"
    fi

    log_success "Migrated to type: web update manager"
}

# Remove unsupported options from the helixscreen update_manager section.
# type: web only supports: type, channel, repo, path.
# Options like persistent_files, managed_services, and install_script are
# not supported and cause Moonraker to log "unparsed config option" warnings.
# Args: $1 = moonraker.conf path
cleanup_unsupported_options() {
    local conf="$1"

    # Check if any unsupported options exist in the helixscreen section.
    # persistent_files has indented continuation lines; the others are single-line.
    if ! awk '
        /^\[update_manager helixscreen\]/{found=1; next}
        found && /^\[/{exit}
        found && /^(persistent_files|managed_services|install_script):/{print; exit}
    ' "$conf" | grep -q .; then
        return 0
    fi

    log_info "Removing unsupported options from [update_manager helixscreen]"
    local fs
    fs=$(file_sudo "$conf")
    $fs cp "$conf" "${conf}.bak.helixscreen" 2>/dev/null || true

    # Remove matching key: lines within the helixscreen section.
    # persistent_files also has indented continuation lines (4-space indent).
    $fs awk '
        /^\[update_manager helixscreen\]/ { in_section=1 }
        in_section && /^\[/ && !/^\[update_manager helixscreen\]/ { in_section=0 }
        in_section && /^(persistent_files|managed_services|install_script):/ { skip_block=1; next }
        skip_block && /^    / { next }
        skip_block { skip_block=0 }
        { print }
    ' "$conf" > "${conf}.tmp" && $fs mv "${conf}.tmp" "$conf"

    log_success "Cleaned up unsupported options from moonraker.conf"
}

# Write release_info.json if not already present
# Moonraker type:web needs this file to detect installed version
write_release_info() {
    local release_info="${INSTALL_DIR}/release_info.json"

    if [ -f "$release_info" ]; then
        return 0
    fi

    # Try to detect version from binary
    local version=""
    if [ -x "${INSTALL_DIR}/bin/helix-screen" ]; then
        version=$("${INSTALL_DIR}/bin/helix-screen" --version 2>/dev/null | head -n 1 | grep -oE 'v[0-9]+\.[0-9]+\.[0-9]+[^ ]*' || echo "")
    fi

    if [ -z "$version" ]; then
        log_warn "Could not detect version for release_info.json"
        return 0
    fi

    # Determine platform-specific asset name
    local asset_name="helixscreen-pi.zip"
    case "${PLATFORM:-}" in
        pi32)       asset_name="helixscreen-pi32.zip" ;;
        ad5m)       asset_name="helixscreen-ad5m.zip" ;;
        ad5x)       asset_name="helixscreen-k1.zip" ;;
        k1)         asset_name="helixscreen-k1.zip" ;;
        k1-dynamic) asset_name="helixscreen-k1-dynamic.zip" ;;
        k2)         asset_name="helixscreen-k2.zip" ;;
    esac

    log_info "Writing release_info.json (${version})..."
    cat > "${release_info}.tmp" << EOF
{"project_name":"helixscreen","project_owner":"prestonbrown","version":"${version}","asset_name":"${asset_name}"}
EOF
    # Try without sudo first (self-update: INSTALL_DIR is user-owned under NoNewPrivileges).
    # Fall back to sudo for fresh installs where the directory may be root-owned.
    mv "${release_info}.tmp" "$release_info" 2>/dev/null || \
        $SUDO mv "${release_info}.tmp" "$release_info" 2>/dev/null || true
}

# Ensure helixscreen is in moonraker.asvc (service allowlist)
# Moonraker requires services to be listed here before it can manage them.
# The asvc file lives in printer_data/, one level up from config/moonraker.conf.
# Args: $1 = moonraker.conf path (used to derive printer_data path)
ensure_moonraker_asvc() {
    local conf="$1"
    # printer_data is two levels up from config/moonraker.conf
    local printer_data
    printer_data="$(dirname "$(dirname "$conf")")"
    local asvc="${printer_data}/moonraker.asvc"

    if [ ! -f "$asvc" ]; then
        log_info "No moonraker.asvc found at $asvc, skipping"
        return 0
    fi

    if grep -q '^helixscreen$' "$asvc" 2>/dev/null; then
        return 0
    fi

    local fs
    fs=$(file_sudo "$asvc")
    log_info "Adding helixscreen to $asvc..."
    # Ensure file ends with a newline before appending (#408)
    if [ -s "$asvc" ] && [ "$(tail -c 1 "$asvc" | wc -l)" -eq 0 ]; then
        echo "" | $fs tee -a "$asvc" >/dev/null
    fi
    echo "helixscreen" | $fs tee -a "$asvc" >/dev/null
    log_success "Added helixscreen to Moonraker service allowlist"
}

# Restart Moonraker to pick up configuration changes
restart_moonraker() {
    if command -v systemctl >/dev/null 2>&1 && systemctl is-active --quiet moonraker 2>/dev/null; then
        log_info "Restarting Moonraker to apply configuration..."
        $SUDO systemctl restart moonraker || true
    elif [ -x "/etc/init.d/S56moonraker_service" ]; then
        # K1/Simple AF uses SysV init
        log_info "Restarting Moonraker to apply configuration..."
        if ! $SUDO /etc/init.d/S56moonraker_service restart 2>/dev/null; then
            log_warn "Could not restart Moonraker - you may need to restart it manually"
        fi
    fi
}

# Configure Moonraker update_manager
# Called during installation on platforms with web UI (Pi, K1 with Simple AF)
configure_moonraker_updates() {
    local platform=$1

    # Skip on AD5M (stock Flashforge firmware lacks Mainsail/Fluidd).
    # NOTE: AD5X is intentionally NOT skipped — it's only ever installed via the
    # ZMOD chroot, which ships Mainsail/Fluidd.
    if [ "$platform" = "ad5m" ]; then
        log_info "Skipping Moonraker update_manager on AD5M (typically no web UI)"
        return 0
    fi

    log_info "Configuring Moonraker update_manager..."

    # Write release_info.json if not already present (fallback for older tarballs)
    write_release_info

    local conf
    conf=$(find_moonraker_conf)

    if [ -z "$conf" ]; then
        log_warn "Could not find moonraker.conf in any known location:"
        if [ -n "${KLIPPER_HOME:-}" ]; then
            log_warn "  ${KLIPPER_HOME}/printer_data/config/moonraker.conf"
        fi
        for tried in $MOONRAKER_CONF_PATHS; do
            log_warn "  $tried"
        done
        log_warn "To enable web UI updates, manually add to your moonraker.conf:"
        echo ""
        generate_update_manager_config
        echo ""
        return 0
    fi

    log_info "Using moonraker.conf at: $conf"

    # Migrate old git_repo or zip config to type: web
    # (type: zip shows perpetual UP-TO-DATE in Mainsail — see mainsail-crew/mainsail#2444)
    if has_old_git_repo_section "$conf" || has_old_zip_section "$conf"; then
        migrate_to_web_type "$conf"
        ensure_moonraker_asvc "$conf"
        restart_moonraker
        return 0
    fi

    if has_update_manager_section "$conf"; then
        log_info "update_manager section already exists in $conf"
        # Remove options not supported by type: web (persistent_files,
        # managed_services, install_script) that cause Moonraker warnings.
        cleanup_unsupported_options "$conf"
        # Still ensure asvc is correct even if section already exists
        ensure_moonraker_asvc "$conf"
        return 0
    fi

    add_update_manager_section "$conf"
    ensure_moonraker_asvc "$conf"
    restart_moonraker
}

# Remove update_manager section from moonraker.conf
# Called during uninstallation
remove_update_manager_section() {
    local conf
    conf=$(find_moonraker_conf)

    if [ -z "$conf" ]; then
        return 0
    fi

    if ! has_update_manager_section "$conf"; then
        return 0
    fi

    log_info "Removing update_manager section from $conf..."

    # Create backup
    local fs
    fs=$(file_sudo "$conf")
    $fs cp "$conf" "${conf}.bak.helixscreen-uninstall" 2>/dev/null || true

    # Remove the section (from [update_manager helixscreen] to next section or EOF)
    # This uses awk to skip lines between [update_manager helixscreen] and the next [section]
    $fs sh -c "awk '
        /^\[update_manager helixscreen\]/ { skip=1; next }
        /^\[/ { skip=0 }
        !skip { print }
    ' \"$conf\" > \"${conf}.tmp\"" && $fs mv "${conf}.tmp" "$conf"

    # Also remove any "Added by HelixScreen" comment lines that precede it
    $fs sed -i '/# HelixScreen Update Manager/d' "$conf" 2>/dev/null || \
    $fs sed -i '' '/# HelixScreen Update Manager/d' "$conf" 2>/dev/null || true

    $fs sed -i '/# Added by HelixScreen installer/d' "$conf" 2>/dev/null || \
    $fs sed -i '' '/# Added by HelixScreen installer/d' "$conf" 2>/dev/null || true

    log_success "Removed update_manager section from $conf"
}

# ============================================
# Module: uninstall.sh
# ============================================

#
# Sentinel paths checked by helixscreen-update.service so it refuses to fire
# while an uninstall is in progress (closes a race where the update path unit
# could trigger a restart between stop_service and rm -rf $INSTALL_DIR).
# Two locations cover both systemd-with-StateDirectory and the bare fallback;
# both live outside $INSTALL_DIR so they survive its removal.  Both are swept
# by clean_helix_state_dirs at the end of uninstall and by the EXIT/INT/TERM
# trap if an uninstall aborts before reaching the sweep (otherwise a stuck
# sentinel silently blocks every future update.service firing).
#
# Honors $HELIX_STATE_VAR_LIB so this stays consistent with the env-override
# the BATS suite uses to redirect clean_helix_state_dirs away from real
# /var/lib.  Production callers leave it unset; the systemd unit hardcodes
# /var/lib/helixscreen/.uninstalling because @@HELIX_STATE_VAR_LIB@@ isn't a
# template var.
_uninstalling_sentinel_paths() {
    echo "${HELIX_STATE_VAR_LIB:-/var/lib/helixscreen}/.uninstalling"
    if [ -n "${INSTALL_DIR:-}" ]; then
        local _parent
        _parent=$(dirname "$INSTALL_DIR" 2>/dev/null || true)
        case "$_parent" in
            /|.|"") : ;;
            *) echo "${_parent}/.helixscreen/.uninstalling" ;;
        esac
    fi
}

_drop_uninstalling_sentinel() {
    local _p _dir
    _uninstalling_sentinel_paths | while IFS= read -r _p; do
        [ -z "$_p" ] && continue
        _dir=$(dirname "$_p")
        $SUDO mkdir -p "$_dir" 2>/dev/null || true
        $SUDO touch "$_p" 2>/dev/null || true
    done
}

# Sweep sentinel files.  Wired to EXIT/INT/TERM in uninstall() so an aborted
# run doesn't leave a stuck sentinel blocking helixscreen-update.service.
# On a successful uninstall this is a no-op — clean_helix_state_dirs already
# removed them — but the trap fires either way.
_sweep_uninstalling_sentinel() {
    local _p
    _uninstalling_sentinel_paths 2>/dev/null | while IFS= read -r _p; do
        [ -z "$_p" ] && continue
        $SUDO rm -f "$_p" 2>/dev/null || true
    done
}

# Re-enable services that were disabled during installation
# Reads the state file and reverses each recorded disable action
reenable_disabled_services() {
    local state_file="${INSTALL_DIR}/config/.disabled_services"
    [ -f "$state_file" ] || return 0

    log_info "Re-enabling previously disabled services..."
    while IFS= read -r entry; do
        # Skip empty lines and comments
        case "$entry" in ""|\#*) continue ;; esac

        local type="${entry%%:*}"
        local target="${entry#*:}"

        case "$type" in
            systemd)
                log_info "Re-enabling systemd service: $target"
                $SUDO systemctl enable "$target" 2>/dev/null || true
                ;;
            sysv-chmod)
                if [ -f "$target" ]; then
                    log_info "Re-enabling init script: $target"
                    $SUDO chmod +x "$target" 2>/dev/null || true
                fi
                ;;
        esac
    done < "$state_file"
}

# Uninstall HelixScreen
# Args: platform (optional)
uninstall() {
    local platform=${1:-}

    log_info "Uninstalling HelixScreen..."

    # Drop sentinel BEFORE any destructive work.  helixscreen-update.service
    # checks for it and refuses to fire while uninstall is running, closing
    # the race where Moonraker's path unit could re-trigger a restart between
    # stop_service and rm -rf.  Swept at the end by clean_helix_state_dirs;
    # the trap covers the abort case so a stuck sentinel can't silently block
    # future update.service firings.
    trap '_sweep_uninstalling_sentinel' EXIT INT TERM
    _drop_uninstalling_sentinel

    # Remove the [update_manager helixscreen] section FIRST, before any files
    # disappear.  If Moonraker auto-refreshes (or someone clicks "Update" in
    # Mainsail mid-uninstall), having the section gone before we start
    # dismantling files prevents a re-extract from racing us.  Moonraker's
    # in-memory updater object survives until Moonraker is reloaded, but
    # type:web only extracts on explicit user trigger so the on-disk edit is
    # the effective fix; no moonraker restart needed.
    if type remove_update_manager_section >/dev/null 2>&1; then
        remove_update_manager_section || true
    fi

    # Detect init system first
    detect_init_system

    if [ "$INIT_SYSTEM" = "systemd" ]; then
        # Stop and disable systemd service
        $SUDO systemctl stop "$SERVICE_NAME" 2>/dev/null || true
        $SUDO systemctl disable "$SERVICE_NAME" 2>/dev/null || true
        $SUDO rm -f "/etc/systemd/system/${SERVICE_NAME}.service"
        # Remove update watcher units (mainsail#2444 workaround)
        $SUDO systemctl stop helixscreen-update.path 2>/dev/null || true
        $SUDO systemctl disable helixscreen-update.path 2>/dev/null || true
        $SUDO rm -f /etc/systemd/system/helixscreen-update.path
        $SUDO rm -f /etc/systemd/system/helixscreen-update.service
        # Remove permission rules (udev, polkit)
        $SUDO rm -f /etc/udev/rules.d/99-helixscreen-backlight.rules
        $SUDO rm -f /etc/polkit-1/localauthority/50-local.d/helixscreen-network.pkla
        $SUDO rm -f /etc/polkit-1/rules.d/49-helixscreen-network.rules
        $SUDO rm -f /etc/polkit-1/rules.d/50-helixscreen-network.rules
        $SUDO systemctl daemon-reload
    else
        # Stop and remove SysV init scripts (check all possible locations)
        local removed_procd_shim=false
        for init_script in $HELIX_INIT_SCRIPTS; do
            if [ -f "$init_script" ]; then
                log_info "Stopping and removing $init_script..."
                $SUDO "$init_script" stop 2>/dev/null || true
                # K2 procd shim: only call disable if this is actually a
                # rc.common-style script. CC1 installs a plain SysV script
                # at the same /etc/init.d/helixscreen path, and CC1's BusyBox
                # rejects `head -1` (only supports `head -n 1`), so we use
                # awk for the shebang check (portable across all BusyBox
                # variants we ship to). Also CC1 has no /etc/rc.common, so
                # the first guard short-circuits anyway.
                if [ "$init_script" = "/etc/init.d/helixscreen" ] && \
                   [ -x /etc/rc.common ] && \
                   awk 'NR==1 {exit !/\/etc\/rc\.common/}' "$init_script" 2>/dev/null; then
                    $SUDO "$init_script" disable 2>/dev/null || true
                    removed_procd_shim=true
                fi
                $SUDO rm -f "$init_script"
            fi
        done
        # Belt-and-suspenders cleanup of rc.d symlinks, but only if we actually
        # removed a procd shim (avoid touching /etc/rc.d on platforms that
        # don't use the procd boot iterator).
        if [ "$removed_procd_shim" = "true" ]; then
            $SUDO rm -f /etc/rc.d/S99helixscreen /etc/rc.d/K01helixscreen 2>/dev/null || true
        fi
    fi

    # Kill any remaining processes (watchdog first to prevent crash dialog flash)
    # shellcheck disable=SC2086
    kill_process_by_name $HELIX_PROCESSES || true

    # Clean up PID files and log file
    $SUDO rm -f /var/run/helixscreen.pid 2>/dev/null || true
    $SUDO rm -f /var/run/helix-splash.pid 2>/dev/null || true
    rm -f /tmp/helixscreen.log 2>/dev/null || true

    # Re-enable services from state file (before removing install dir)
    reenable_disabled_services

    # Remove installation (check all possible locations)
    local removed_dir=""
    for install_dir in $HELIX_INSTALL_DIRS; do
        if [ -d "$install_dir" ]; then
            $SUDO rm -rf "$install_dir"
            log_success "Removed ${install_dir}"
            removed_dir="$install_dir"
            # Also remove the updater repo clone if present
            if [ -d "${install_dir}-repo" ]; then
                $SUDO rm -rf "${install_dir}-repo"
                log_success "Removed ${install_dir}-repo"
            fi
        fi
    done

    if [ -z "$removed_dir" ]; then
        log_warn "No HelixScreen installation found"
    fi

    # Re-enable the previous UI based on firmware
    log_info "Re-enabling previous screen UI..."
    local restored_ui=""
    local restored_xorg=""

    if [ "$AD5M_FIRMWARE" = "klipper_mod" ] || [ -f "/etc/init.d/S80klipperscreen" ]; then
        # Klipper Mod - restore Xorg and KlipperScreen
        if [ -f "/etc/init.d/S40xorg" ]; then
            $SUDO chmod +x "/etc/init.d/S40xorg" 2>/dev/null || true
            restored_xorg="Xorg (/etc/init.d/S40xorg)"
        fi
        if [ -f "/etc/init.d/S80klipperscreen" ]; then
            $SUDO chmod +x "/etc/init.d/S80klipperscreen" 2>/dev/null || true
            restored_ui="KlipperScreen (/etc/init.d/S80klipperscreen)"
        fi
    fi

    # ZMOD - no UI restore needed; S80guppyscreen is managed by ZMOD
    if [ "$AD5M_FIRMWARE" = "zmod" ]; then
        log_info "ZMOD firmware: no previous UI to restore (managed by ZMOD)"
    fi

    # K2 series (Creality K2 Plus / K2 Pro): re-enable the stock procd-managed UI.
    # hooks-k2.sh runs `/etc/init.d/app disable` on every launch (which removes
    # the procd rc.d symlink), so without this step the device boots into the
    # Creality logo with no UI after uninstall.
    if [ -z "$restored_ui" ] && [ -f /etc/init.d/app ] && \
       { [ "$platform" = "k2" ] || [ -f /mnt/UDISK/printer_data/config/printer.cfg ]; }; then
        log_info "Re-enabling Creality stock UI (/etc/init.d/app)..."
        $SUDO /etc/init.d/app enable 2>/dev/null || true
        $SUDO /etc/init.d/app start 2>/dev/null || true
        restored_ui="Creality stock UI (/etc/init.d/app)"
    fi

    # Check for K1/Simple AF GuppyScreen
    if [ -z "$restored_ui" ] && [ "$AD5M_FIRMWARE" != "zmod" ] && [ -f "/etc/init.d/S99guppyscreen" ]; then
        $SUDO chmod +x "/etc/init.d/S99guppyscreen" 2>/dev/null || true
        restored_ui="GuppyScreen (/etc/init.d/S99guppyscreen)"
    fi

    # ForgeX - restore GuppyScreen and stock UI settings
    if [ -z "$restored_ui" ] && [ "$AD5M_FIRMWARE" = "forge_x" ]; then
        uninstall_forgex
    fi

    # COSMOS (Centauri Carbon): restore /etc/init.d/grumpyscreen from the
    # backup the installer made when it substituted in the helixscreen-wrapper
    # init script (see competing_uis.sh stop_cc1_competing_uis). Also revert
    # cosmos.conf in case the upstream config-manager allowlist fix lands and
    # actually starts honoring 'helixscreen' values — we want to be a clean
    # citizen on uninstall regardless.
    if [ -z "$restored_ui" ] && [ -x "/usr/bin/update-cosmos" ]; then
        if [ -f /etc/init.d/grumpyscreen.helix-bak ]; then
            log_info "Restoring original /etc/init.d/grumpyscreen"
            $SUDO mv /etc/init.d/grumpyscreen.helix-bak /etc/init.d/grumpyscreen \
                || log_warn "Could not restore /etc/init.d/grumpyscreen — gui-switcher may not launch a UI on next boot"
        fi
        if [ -f /etc/klipper/config/cosmos.conf ] && \
           grep -q "^screen_ui[[:space:]]*=[[:space:]]*helixscreen" /etc/klipper/config/cosmos.conf 2>/dev/null; then
            log_info "Reverting cosmos.conf screen_ui to grumpyscreen"
            $SUDO sed -i "s|^screen_ui[[:space:]]*=.*|screen_ui = grumpyscreen|" \
                /etc/klipper/config/cosmos.conf 2>/dev/null || true
        fi
        if [ -x /etc/init.d/grumpyscreen ]; then
            log_info "Starting grumpyscreen"
            $SUDO /etc/init.d/grumpyscreen start 2>/dev/null || true
            restored_ui="grumpyscreen (COSMOS stock UI)"
        fi
    fi

    # Clean up helixscreen cache directories
    for cache_dir in /root/.cache/helix /tmp/helix_thumbs /.cache/helix /data/helixscreen/cache /usr/data/helixscreen/cache; do
        if [ -d "$cache_dir" ] 2>/dev/null; then
            log_info "Removing cache: $cache_dir"
            $SUDO rm -rf "$cache_dir"
        fi
    done
    # Clean up /var/tmp helix files
    for tmp_pattern in /var/tmp/helix_*; do
        if [ -e "$tmp_pattern" ] 2>/dev/null; then
            log_info "Removing cache: $tmp_pattern"
            $SUDO rm -rf "$tmp_pattern"
        fi
    done

    # Clean up active flag file
    rm -f /tmp/helixscreen_active 2>/dev/null || true

    # Clean up macOS resource fork files (created by scp from Mac)
    for pattern in /opt/._helixscreen /root/._helixscreen; do
        $(file_sudo "$pattern") rm -f "$pattern" 2>/dev/null || true
    done

    # Remove config symlinks (preserves user files in printer_data)
    if type remove_config_symlink >/dev/null 2>&1; then
        remove_config_symlink || true
    fi

    # Sweep state dirs holding rolling config backups (out-of-INSTALL_DIR by
    # design).  Also sweeps the .uninstalling sentinel dropped at the top.
    clean_helix_state_dirs

    # Strip the legacy [shell_command helix_recover] block from moonraker.conf
    # (dead since v0.99.61 — kept around on already-installed K2s until they
    # next upgrade or, as here, uninstall).
    if type remove_legacy_moonraker_block >/dev/null 2>&1; then
        local _mr_conf
        _mr_conf=$(find_moonraker_conf 2>/dev/null || true)
        if [ -n "$_mr_conf" ] && [ -f "$_mr_conf" ]; then
            remove_legacy_moonraker_block "$_mr_conf" "$(file_sudo "$_mr_conf")" || true
        fi
    fi

    log_success "HelixScreen uninstalled"
    if [ -n "$restored_xorg" ]; then
        log_info "Re-enabled: $restored_xorg"
    fi
    if [ -n "$restored_ui" ]; then
        log_info "Re-enabled: $restored_ui"
        log_info "Reboot to start the previous UI"
    else
        log_info "Note: No previous UI found to restore"
    fi
}

# Clean up old installation completely (for --clean flag)
# Removes all files, config, and caches without backup
# Args: platform
clean_old_installation() {
    local platform=$1

    log_warn "=========================================="
    log_warn "  CLEAN INSTALL MODE"
    log_warn "=========================================="
    log_warn ""
    log_warn "This will PERMANENTLY DELETE:"
    log_warn "  - All HelixScreen files in ${INSTALL_DIR}"
    log_warn "  - Your configuration (settings.json)"
    log_warn "  - Rolling config backups (/var/lib/helixscreen + .helixscreen under the service user's home)"
    log_warn "  - Thumbnail cache files"
    log_warn ""

    # Interactive confirmation if stdin is a terminal
    if [ -t 0 ]; then
        printf "Are you sure? [y/N] "
        read -r response
        case "$response" in
            [yY][eE][sS]|[yY])
                ;;
            *)
                log_info "Clean install cancelled."
                exit 0
                ;;
        esac
    fi

    log_info "Cleaning old installation..."

    # Stop any running services
    stop_service

    # Remove installation directories (check all possible locations)
    for install_dir in $HELIX_INSTALL_DIRS; do
        if [ -d "$install_dir" ]; then
            log_info "Removing $install_dir..."
            $SUDO rm -rf "$install_dir"
        fi
    done

    # Remove thumbnail caches (POSIX-compatible: no arrays)
    for cache_pattern in \
        "/root/.cache/helix/helix_thumbs" \
        "/home/*/.cache/helix/helix_thumbs" \
        "/tmp/helix_thumbs" \
        "/var/tmp/helix_thumbs" \
        "/var/tmp/helix_*" \
        "/data/helixscreen/cache" \
        "/usr/data/helixscreen/cache"
    do
        for cache_dir in $cache_pattern; do
            if [ -d "$cache_dir" ] 2>/dev/null; then
                log_info "Removing cache: $cache_dir"
                $SUDO rm -rf "$cache_dir"
            fi
        done
    done

    # Remove init scripts (check all possible locations)
    for init_script in $HELIX_INIT_SCRIPTS; do
        if [ -f "$init_script" ]; then
            log_info "Removing init script: $init_script"
            $SUDO rm -f "$init_script"
        fi
    done

    # Remove systemd service if present
    if [ -f "/etc/systemd/system/${SERVICE_NAME}.service" ]; then
        log_info "Removing systemd service..."
        $SUDO systemctl disable "$SERVICE_NAME" 2>/dev/null || true
        $SUDO rm -f "/etc/systemd/system/${SERVICE_NAME}.service"
    fi
    # Remove update watcher units
    $SUDO systemctl stop helixscreen-update.path 2>/dev/null || true
    $SUDO systemctl disable helixscreen-update.path 2>/dev/null || true
    $SUDO rm -f /etc/systemd/system/helixscreen-update.path
    $SUDO rm -f /etc/systemd/system/helixscreen-update.service
    # Remove permission rules (udev, polkit)
    $SUDO rm -f /etc/udev/rules.d/99-helixscreen-backlight.rules
    $SUDO rm -f /etc/polkit-1/localauthority/50-local.d/helixscreen-network.pkla
    $SUDO rm -f /etc/polkit-1/rules.d/49-helixscreen-network.rules
    $SUDO rm -f /etc/polkit-1/rules.d/50-helixscreen-network.rules
    $SUDO systemctl daemon-reload 2>/dev/null || true

    # Remove printer_data/config/helixscreen/ (user config) in clean mode
    if [ -n "${KLIPPER_HOME:-}" ]; then
        local pd_helix="${KLIPPER_HOME}/printer_data/config/helixscreen"
        if [ -d "$pd_helix" ] || [ -L "$pd_helix" ]; then
            log_info "Removing user config: $pd_helix"
            $SUDO rm -rf "$pd_helix"
        fi
    fi

    # Sweep state dirs holding rolling config backups
    clean_helix_state_dirs

    log_success "Old installation cleaned"
    echo ""
}

# ============================================
# Main orchestration
# ============================================

# Re-enable previous UI (extended version with scanning)
reenable_previous_ui() {
    log_info "Looking for previous screen UI to re-enable..."

    found_ui=false
    restored_xorg=false

    # For ForgeX firmware, do comprehensive cleanup and restore
    if [ "$AD5M_FIRMWARE" = "forge_x" ]; then
        uninstall_forgex

        if [ -n "$restored_ui" ]; then
            found_ui=true
        fi
    fi

    # For K1/Simple AF, check for GuppyScreen
    if [ "$platform" = "k1" ]; then
        for k1_ui in /etc/init.d/S99guppyscreen /etc/init.d/S50guppyscreen; do
            if [ -f "$k1_ui" ]; then
                log_info "Re-enabling GuppyScreen for K1..."
                $SUDO chmod +x "$k1_ui" 2>/dev/null || true
                if "$k1_ui" start 2>/dev/null; then
                    log_success "Re-enabled and started: $k1_ui"
                    found_ui=true
                    break
                fi
            fi
        done
    fi

    # For Klipper Mod, re-enable Xorg first (required for KlipperScreen)
    if [ "$AD5M_FIRMWARE" = "klipper_mod" ] || [ -f "/etc/init.d/S40xorg" ]; then
        if [ -f "/etc/init.d/S40xorg" ]; then
            log_info "Re-enabling Xorg display server..."
            $SUDO chmod +x "/etc/init.d/S40xorg" 2>/dev/null || true
            restored_xorg=true
        fi
    fi

    # Try the specific previous UI script for this firmware
    if [ -n "$PREVIOUS_UI_SCRIPT" ] && [ -f "$PREVIOUS_UI_SCRIPT" ]; then
        log_info "Found previous UI: $PREVIOUS_UI_SCRIPT"
        $SUDO chmod +x "$PREVIOUS_UI_SCRIPT" 2>/dev/null || true
        if "$PREVIOUS_UI_SCRIPT" start 2>/dev/null; then
            log_success "Re-enabled and started: $PREVIOUS_UI_SCRIPT"
            found_ui=true
        else
            log_warn "Re-enabled but failed to start: $PREVIOUS_UI_SCRIPT"
            log_warn "You may need to reboot"
            found_ui=true
        fi
    fi

    # Scan for other UIs we might have disabled
    for ui in $PREVIOUS_UIS; do
        for initscript in /etc/init.d/S*${ui}* /opt/config/mod/.root/S*${ui}*; do
            [ "$initscript" = "$PREVIOUS_UI_SCRIPT" ] && continue
            if [ -f "$initscript" ] 2>/dev/null; then
                log_info "Found previous UI: $initscript"
                $SUDO chmod +x "$initscript" 2>/dev/null || true
                if [ "$found_ui" = false ]; then
                    if "$initscript" start 2>/dev/null; then
                        log_success "Re-enabled and started: $initscript"
                        found_ui=true
                    else
                        log_warn "Re-enabled but failed to start: $initscript"
                        log_warn "You may need to reboot"
                        found_ui=true
                    fi
                else
                    log_info "Re-enabled: $initscript (not started, another UI already running)"
                fi
            fi
        done

        if [ "$INIT_SYSTEM" = "systemd" ]; then
            if systemctl list-unit-files "${ui}.service" >/dev/null 2>&1; then
                log_info "Found previous UI (systemd): $ui"
                $SUDO systemctl enable "$ui" 2>/dev/null || true
                if $SUDO systemctl start "$ui" 2>/dev/null; then
                    log_success "Re-enabled and started: $ui"
                    found_ui=true
                else
                    log_warn "Re-enabled but failed to start: $ui"
                    found_ui=true
                fi
            fi
        fi
    done

    # Re-enable tslib for ForgeX (if not already handled by uninstall_forgex)
    if [ -f "/opt/config/mod/.root/S35tslib" ]; then
        $SUDO chmod +x "/opt/config/mod/.root/S35tslib" 2>/dev/null || true
    fi

    if [ "$found_ui" = false ]; then
        log_info "No previous screen UI found to re-enable"
        log_info "If you had a stock UI, a reboot may restore it"
    fi

    if [ "$restored_xorg" = true ]; then
        log_info "Re-enabled: Xorg (/etc/init.d/S40xorg)"
    fi
}

# Stop HelixScreen processes and service
stop_helixscreen() {
    log_info "Stopping HelixScreen..."

    # Stop via init system
    if [ "$INIT_SYSTEM" = "systemd" ]; then
        $SUDO systemctl stop helixscreen 2>/dev/null || true
        $SUDO systemctl disable helixscreen 2>/dev/null || true
    fi

    # Stop via configured init script
    if [ -n "$INIT_SCRIPT_DEST" ] && [ -x "$INIT_SCRIPT_DEST" ]; then
        $SUDO "$INIT_SCRIPT_DEST" stop 2>/dev/null || true
    fi

    # Also check all possible init script locations
    for init_script in $HELIX_INIT_SCRIPTS; do
        if [ -x "$init_script" ]; then
            $SUDO "$init_script" stop 2>/dev/null || true
        fi
    done

    # Kill any remaining processes (watchdog first to prevent crash dialog flash)
    # shellcheck disable=SC2086
    kill_process_by_name $HELIX_PROCESSES || true

    log_success "HelixScreen stopped"
}

# Remove init script or systemd service
remove_service() {
    log_info "Removing service configuration..."

    if [ "$INIT_SYSTEM" = "systemd" ]; then
        if [ -f "/etc/systemd/system/helixscreen.service" ]; then
            $SUDO rm -f "/etc/systemd/system/helixscreen.service"
            $SUDO systemctl daemon-reload
            log_success "Removed systemd service"
        fi
    fi

    # Remove configured init script
    if [ -n "$INIT_SCRIPT_DEST" ] && [ -f "$INIT_SCRIPT_DEST" ]; then
        $SUDO rm -f "$INIT_SCRIPT_DEST"
        log_success "Removed SysV init script: $INIT_SCRIPT_DEST"
    fi

    # Also check and remove from all possible locations
    for init_script in $HELIX_INIT_SCRIPTS; do
        if [ -f "$init_script" ]; then
            $SUDO rm -f "$init_script"
            log_success "Removed SysV init script: $init_script"
        fi
    done
}

# Remove installation directory
remove_installation() {
    log_info "Removing installation..."

    removed_any=false

    # Re-enable services from state file BEFORE removing install dir
    reenable_disabled_services

    # Remove from configured location
    if [ -d "$INSTALL_DIR" ]; then
        $SUDO rm -rf "$INSTALL_DIR"
        log_success "Removed $INSTALL_DIR"
        removed_any=true
        # Also remove updater repo clone if present
        if [ -d "${INSTALL_DIR}-repo" ]; then
            $SUDO rm -rf "${INSTALL_DIR}-repo"
            log_success "Removed ${INSTALL_DIR}-repo"
        fi
    fi

    # Also check and remove from all possible locations
    for install_dir in $HELIX_INSTALL_DIRS; do
        if [ -d "$install_dir" ] && [ "$install_dir" != "$INSTALL_DIR" ]; then
            $SUDO rm -rf "$install_dir"
            log_success "Removed $install_dir"
            removed_any=true
            if [ -d "${install_dir}-repo" ]; then
                $SUDO rm -rf "${install_dir}-repo"
                log_success "Removed ${install_dir}-repo"
            fi
        fi
    done

    if [ "$removed_any" = false ]; then
        log_warn "No HelixScreen installation found (already removed?)"
    fi

    # Clean up PID files, log file, and active flag
    $SUDO rm -f /var/run/helixscreen.pid 2>/dev/null || true
    $SUDO rm -f /var/run/helix-splash.pid 2>/dev/null || true
    $SUDO rm -f /tmp/helixscreen.log 2>/dev/null || true
    $SUDO rm -f /tmp/helixscreen_active 2>/dev/null || true

    # Clean up cache directories
    for cache_dir in /root/.cache/helix /tmp/helix_thumbs /.cache/helix; do
        if [ -d "$cache_dir" ] 2>/dev/null; then
            log_info "Removing cache: $cache_dir"
            $SUDO rm -rf "$cache_dir"
        fi
    done

    # Clean up macOS resource fork files (created by scp from Mac)
    for pattern in /opt/._helixscreen /root/._helixscreen; do
        $SUDO rm -f "$pattern" 2>/dev/null || true
    done

    # Sweep state dirs holding rolling config backups (out-of-INSTALL_DIR by design).
    # Defined in lib/installer/common.sh; bundled into this script.
    clean_helix_state_dirs
}

# Refuse to run if $0 lives inside $INSTALL_DIR — we're about to delete
# that directory and would yank the script out from under ourselves mid-run.
# Tell the user how to re-invoke from /tmp.  Called from main() after
# set_install_paths so $INSTALL_DIR is populated.  Normalizes a trailing
# slash so an INSTALL_DIR override like "/opt/helixscreen/" still matches.
guard_self_delete() {
    [ -n "${INSTALL_DIR:-}" ] || return 0

    local _script_dir _script_abs _install_norm
    _script_dir="$(cd "$(dirname "$0")" 2>/dev/null && pwd)" || return 0
    _script_abs="${_script_dir}/$(basename "$0")"
    _install_norm="${INSTALL_DIR%/}"

    case "$_script_abs" in
        "$_install_norm"/*|"$_install_norm")
            log_error "Refusing to run: uninstall script is inside \$INSTALL_DIR"
            log_error "  script:      $_script_abs"
            log_error "  INSTALL_DIR: $INSTALL_DIR"
            log_error ""
            log_error "This script is about to delete its own directory.  Copy it"
            log_error "out first, then re-run from the copy:"
            log_error "  cp '$_script_abs' /tmp/uninstall.sh"
            log_error "  sh /tmp/uninstall.sh $*"
            exit 1
            ;;
    esac
}

# Main uninstall
main() {
    force=false

    # Parse arguments
    while [ $# -gt 0 ]; do
        case "$1" in
            --force|-f)
                force=true
                shift
                ;;
            --help|-h)
                echo "HelixScreen Uninstaller"
                echo ""
                echo "Usage: $0 [options]"
                echo ""
                echo "Options:"
                echo "  --force, -f   Skip confirmation prompt"
                echo "  --help, -h    Show this help message"
                exit 0
                ;;
            *)
                log_error "Unknown option: $1"
                exit 1
                ;;
        esac
    done

    echo ""
    echo "${CYAN}========================================${NC}"
    echo "${CYAN}     HelixScreen Uninstaller${NC}"
    echo "${CYAN}========================================${NC}"
    echo ""

    # Detect platform and firmware to set correct paths
    platform=$(detect_platform)
    if [ "$platform" = "ad5x" ]; then
        ad5x_check_chroot_context
    fi
    if [ "$platform" = "ad5m" ]; then
        AD5M_FIRMWARE=$(detect_ad5m_firmware)
        log_info "Detected AD5M firmware: $AD5M_FIRMWARE"
    fi
    set_install_paths "$platform" "$AD5M_FIRMWARE"

    # Refuse to self-delete (must be after set_install_paths)
    guard_self_delete "$@"

    # Check for root
    check_permissions "$platform"

    # Detect init system
    detect_init_system

    # Confirm unless --force
    if [ "$force" = false ]; then
        echo "This will:"
        echo "  - Stop HelixScreen"
        echo "  - Remove $INSTALL_DIR"
        echo "  - Remove service configuration"
        echo "  - Remove rolling config backups (/var/lib/helixscreen + .helixscreen under the service user's home)"
        echo "  - Re-enable previous screen UI (if found)"
        if [ "$AD5M_FIRMWARE" = "forge_x" ]; then
            echo "  - Restore ForgeX display configuration (GuppyScreen)"
        fi
        echo ""
        printf "Are you sure you want to continue? [y/N] "
        read -r response
        case "$response" in
            [yY][eE][sS]|[yY])
                ;;
            *)
                log_info "Uninstall cancelled"
                exit 0
                ;;
        esac
        echo ""
    fi

    # Perform uninstall.  Order matters:
    #   1. Drop .uninstalling sentinel so helixscreen-update.service refuses
    #      to fire while we're working.  Trap on EXIT/INT/TERM covers an
    #      aborted run so a stuck sentinel doesn't silently block all future
    #      update.service firings.
    #   2. Edit moonraker.conf FIRST.  If anything races us (auto-refresh,
    #      a user clicking Update in Mainsail), having the section gone
    #      before we start dismantling files is the on-disk defense; the
    #      systemd path-unit defense (sentinel) covers the in-process side.
    #   3. Stop, remove, sweep — sweep also clears the sentinel via
    #      clean_helix_state_dirs.
    trap '_sweep_uninstalling_sentinel' EXIT INT TERM
    _drop_uninstalling_sentinel
    remove_update_manager_section || true
    stop_helixscreen
    remove_service
    remove_installation
    reenable_previous_ui

    echo ""
    echo "${GREEN}========================================${NC}"
    echo "${GREEN}    Uninstall Complete!${NC}"
    echo "${GREEN}========================================${NC}"
    echo ""
    log_info "HelixScreen has been removed."
    log_info "A reboot is recommended to ensure clean state."
    echo ""
}

# Only run when executed directly (not when sourced for testing)
case "${0##*/}" in
    uninstall.sh) main "$@" ;;
esac
